package re.chasam.voicetastic.model
/** * Unified chat item representing either a text or voice message * in a single chronological conversation stream. */ sealed class ChatItem { abstract val id: Int abstract val from: String abstract val to: String abstract val timestamp: Long abstract val isOutgoing: Boolean abstract val channel: Int
data class Text( override val id: Int, override val from: String, override val to: String, override val timestamp: Long = System.currentTimeMillis(), override val isOutgoing: Boolean = false, val text: String, override val channel: Int = 0 ) : ChatItem()
data class Voice( override val id: Int, override val from: String, override val to: String, override val timestamp: Long = System.currentTimeMillis(), override val isOutgoing: Boolean = false, val audioData: ByteArray, val isComplete: Boolean = true, val totalChunks: Int = 0, val receivedChunks: Int = 0, val bitrateIndex: Int = 0, override val channel: Int = 0 ) : ChatItem() { override fun equals(other: Any?): Boolean { if (this === other) return true if (other !is Voice) return false return id == other.id && from == other.from }
override fun hashCode(): Int = 31 * id + from.hashCode() } }

package re.chasam.voicetastic.model
/** * Unified chat item representing either a text or voice message. * * `contactKey` identifies the conversation this message belongs to: * - "broadcast" → the channel/group broadcast conversation * - a node ID (e.g. "!12345678") → a direct conversation with that node * * The contact key is computed deterministically when the message is ingested, * so filtering becomes a simple equality check (no perspective-dependent * re-computation at view time). */ sealed class ChatItem { abstract val id: Int abstract val from: String abstract val to: String abstract val timestamp: Long abstract val isOutgoing: Boolean abstract val channel: Int abstract val contactKey: String
data class Text( override val id: Int, override val from: String, override val to: String, override val timestamp: Long = System.currentTimeMillis(), override val isOutgoing: Boolean = false, val text: String, override val channel: Int = 0, override val contactKey: String = "broadcast" ) : ChatItem()
data class Voice( override val id: Int, override val from: String, override val to: String, override val timestamp: Long = System.currentTimeMillis(), override val isOutgoing: Boolean = false, val audioData: ByteArray, val isComplete: Boolean = true, val totalChunks: Int = 0, val receivedChunks: Int = 0, val bitrateIndex: Int = 0, override val channel: Int = 0, override val contactKey: String = "broadcast" ) : ChatItem() { override fun equals(other: Any?): Boolean { if (this === other) return true if (other !is Voice) return false return id == other.id && from == other.from }
override fun hashCode(): Int = 31 * id + from.hashCode() } }

package re.chasam.voicetastic.ui.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.geeksville.mesh.MeshProtos
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import re.chasam.voicetastic.model.AmrNbBitrate
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.service.MeshServiceManager

/**
 * ViewModel for the settings/configuration screen.
 * Manages Meshtastic device config (all sections), channels, owner, modules, and app voice config.
 * Observes config flows from MeshServiceManager and populates UI state on connection.
 */
class ConfigViewModel(
    private val meshService: MeshServiceManager,
    private val voiceConfig: MutableStateFlow<VoiceConfig>
) : ViewModel() {

    val connectionState: StateFlow<String> = meshService.connectionState
    val myNodeId: StateFlow<String?> = meshService.myNodeId
    val firmwareVersion: StateFlow<String?> = meshService.firmwareVersion

    // --- Status ---
    private val _configStatus = MutableStateFlow<String?>(null)
    val configStatus: StateFlow<String?> = _configStatus.asStateFlow()

    // ========================  OWNER  ========================

    data class OwnerUiState(
        val longName: String = "",
        val shortName: String = "",
        val isLicensed: Boolean = false
    )

    private val _ownerState = MutableStateFlow(OwnerUiState())
    val ownerState: StateFlow<OwnerUiState> = _ownerState.asStateFlow()

    // ========================  LORA  ========================

    data class LoraUiState(
        val region: String = "UNSET",
        val modemPreset: String = "LONG_FAST",
        val usePreset: Boolean = true,
        val bandwidth: Int = 0,
        val spreadFactor: Int = 0,
        val codingRate: Int = 0,
        val frequencyOffset: Float = 0f,
        val hopLimit: Int = 3,
        val txEnabled: Boolean = true,
        val txPower: Int = 0,
        val channelNum: Int = 0,
        val overrideDutyCycle: Boolean = false,
        val sx126xRxBoostedGain: Boolean = false,
        val overrideFrequency: Float = 0f,
        val ignoreMqtt: Boolean = false
    )

    private val _loraState = MutableStateFlow(LoraUiState())
    val loraState: StateFlow<LoraUiState> = _loraState.asStateFlow()

    val regions = listOf(
        "UNSET", "US", "EU_433", "EU_868", "CN", "JP", "ANZ", "KR",
        "TW", "RU", "IN", "NZ_865", "TH", "LORA_24", "UA_433", "UA_868"
    )

    val modemPresets = listOf(
        "LONG_FAST", "LONG_SLOW", "VERY_LONG_SLOW",
        "MEDIUM_SLOW", "MEDIUM_FAST",
        "SHORT_SLOW", "SHORT_FAST", "LONG_MODERATE", "SHORT_TURBO"
    )

    // ========================  DEVICE  ========================

    data class DeviceUiState(
        val role: String = "CLIENT",
        val serialEnabled: Boolean = false,
        val debugLogEnabled: Boolean = false,
        val buttonGpio: Int = 0,
        val buzzerGpio: Int = 0,
        val rebroadcastMode: String = "ALL",
        val nodeInfoBroadcastSecs: Int = 0,
        val doubleTapAsButtonPress: Boolean = false,
        val isManaged: Boolean = false,
        val disableTripleClick: Boolean = false
    )

    private val _deviceState = MutableStateFlow(DeviceUiState())
    val deviceState: StateFlow<DeviceUiState> = _deviceState.asStateFlow()

    val deviceRoles = listOf(
        "CLIENT", "CLIENT_MUTE", "ROUTER", "ROUTER_CLIENT", "REPEATER",
        "TRACKER", "SENSOR", "TAK", "CLIENT_HIDDEN", "LOST_AND_FOUND", "TAK_TRACKER"
    )

    val rebroadcastModes = listOf("ALL", "ALL_SKIP_DECODING", "LOCAL_ONLY", "KNOWN_ONLY")

    // ========================  POSITION  ========================

    data class PositionUiState(
        val positionBroadcastSecs: Int = 0,
        val positionBroadcastSmartEnabled: Boolean = false,
        val fixedPosition: Boolean = false,
        val gpsEnabled: Boolean = true,
        val gpsUpdateInterval: Int = 0,
        val gpsMode: String = "ENABLED",
        val broadcastSmartMinimumDistance: Int = 0,
        val broadcastSmartMinimumIntervalSecs: Int = 0
    )

    private val _positionState = MutableStateFlow(PositionUiState())
    val positionState: StateFlow<PositionUiState> = _positionState.asStateFlow()

    val gpsModes = listOf("DISABLED", "ENABLED", "NOT_PRESENT")

    // ========================  POWER  ========================

    data class PowerUiState(
        val isPowerSaving: Boolean = false,
        val onBatteryShutdownAfterSecs: Int = 0,
        val adcMultiplierOverride: Float = 0f,
        val waitBluetoothSecs: Int = 0,
        val sdsSecs: Int = 0,
        val lsSecs: Int = 0,
        val minWakeSecs: Int = 0,
        val shutdownOnPowerLoss: Boolean = false
    )

    private val _powerState = MutableStateFlow(PowerUiState())
    val powerState: StateFlow<PowerUiState> = _powerState.asStateFlow()

    // ========================  NETWORK  ========================

    data class NetworkUiState(
        val wifiEnabled: Boolean = false,
        val wifiSsid: String = "",
        val wifiPsk: String = "",
        val ethEnabled: Boolean = false,
        val addressMode: String = "DHCP",
        val ntpServer: String = "",
        val rsyslogServer: String = ""
    )

    private val _networkState = MutableStateFlow(NetworkUiState())
    val networkState: StateFlow<NetworkUiState> = _networkState.asStateFlow()

    val addressModes = listOf("DHCP", "STATIC")

    // ========================  DISPLAY  ========================

    data class DisplayUiState(
        val screenOnSecs: Int = 0,
        val gpsFormat: String = "DEC",
        val autoScreenCarouselSecs: Int = 0,
        val compassNorthTop: Boolean = false,
        val flipScreen: Boolean = false,
        val units: String = "METRIC",
        val oled: String = "OLED_AUTO",
        val displaymode: String = "DEFAULT",
        val headingBold: Boolean = false,
        val wakeOnTapOrMotion: Boolean = false
    )

    private val _displayState = MutableStateFlow(DisplayUiState())
    val displayState: StateFlow<DisplayUiState> = _displayState.asStateFlow()

    val gpsFormats = listOf("DEC", "DMS", "UTM", "MGRS", "OLC", "OSGR")
    val displayUnits = listOf("METRIC", "IMPERIAL")
    val oledTypes = listOf("OLED_AUTO", "OLED_SSD1306", "OLED_SH1106", "OLED_SH1107")
    val displayModes = listOf("DEFAULT", "TWOCOLOR", "INVERTED", "COLOR")

    // ========================  BLUETOOTH  ========================

    data class BluetoothUiState(
        val enabled: Boolean = true,
        val mode: String = "RANDOM_PIN",
        val fixedPin: Int = 0
    )

    private val _bluetoothState = MutableStateFlow(BluetoothUiState())
    val bluetoothState: StateFlow<BluetoothUiState> = _bluetoothState.asStateFlow()

    val pairingModes = listOf("RANDOM_PIN", "FIXED_PIN", "NO_PIN")

    // ========================  CHANNELS  ========================

    data class ChannelUiState(
        val index: Int = 0,
        val role: String = "DISABLED",
        val name: String = "",
        val pskHex: String = "",
        val uplinkEnabled: Boolean = false,
        val downlinkEnabled: Boolean = false
    )

    private val _channelsState = MutableStateFlow<List<ChannelUiState>>(emptyList())
    val channelsState: StateFlow<List<ChannelUiState>> = _channelsState.asStateFlow()

    val channelRoles = listOf("DISABLED", "PRIMARY", "SECONDARY")

    // ========================  VOICE CONFIG  ========================

    val currentVoiceConfig: StateFlow<VoiceConfig> = voiceConfig.asStateFlow()

    // ========================  INIT — FLOW COLLECTION  ========================

    init {
        // Observe LoRa config from device
        viewModelScope.launch {
            meshService.radioConfig.filterNotNull().collect { lora ->
                val regionName = lora.region.let {
                    if (it == MeshProtos.Config.LoRaConfig.RegionCode.UNRECOGNIZED) "UNSET" else it.name
                }
                val presetName = lora.modemPreset.let {
                    if (it == MeshProtos.Config.LoRaConfig.ModemPreset.UNRECOGNIZED) "LONG_FAST" else it.name
                }
                _loraState.value = LoraUiState(
                    region = regionName,
                    modemPreset = presetName,
                    usePreset = lora.usePreset,
                    bandwidth = lora.bandwidth,
                    spreadFactor = lora.spreadFactor,
                    codingRate = lora.codingRate,
                    frequencyOffset = lora.frequencyOffset,
                    hopLimit = lora.hopLimit,
                    txEnabled = lora.txEnabled,
                    txPower = lora.txPower,
                    channelNum = lora.channelNum,
                    overrideDutyCycle = lora.overrideDutyCycle,
                    sx126xRxBoostedGain = lora.sx126XRxBoostedGain,
                    overrideFrequency = lora.overrideFrequency,
                    ignoreMqtt = lora.ignoreMqtt
                )
            }
        }

        // Observe Device config
        viewModelScope.launch {
            meshService.deviceConfig.filterNotNull().collect { dev ->
                _deviceState.value = DeviceUiState(
                    role = dev.role.name,
                    serialEnabled = dev.serialEnabled,
                    debugLogEnabled = dev.debugLogEnabled,
                    buttonGpio = dev.buttonGpio,
                    buzzerGpio = dev.buzzerGpio,
                    rebroadcastMode = dev.rebroadcastMode.name,
                    nodeInfoBroadcastSecs = dev.nodeInfoBroadcastSecs,
                    doubleTapAsButtonPress = dev.doubleTapAsButtonPress,
                    isManaged = dev.isManaged,
                    disableTripleClick = dev.disableTripleClick
                )
            }
        }

        // Observe Position config
        viewModelScope.launch {
            meshService.positionConfig.filterNotNull().collect { pos ->
                _positionState.value = PositionUiState(
                    positionBroadcastSecs = pos.positionBroadcastSecs,
                    positionBroadcastSmartEnabled = pos.positionBroadcastSmartEnabled,
                    fixedPosition = pos.fixedPosition,
                    gpsEnabled = pos.gpsEnabled,
                    gpsUpdateInterval = pos.gpsUpdateInterval,
                    gpsMode = pos.gpsMode.name,
                    broadcastSmartMinimumDistance = pos.broadcastSmartMinimumDistance,
                    broadcastSmartMinimumIntervalSecs = pos.broadcastSmartMinimumIntervalSecs
                )
            }
        }

        // Observe Power config
        viewModelScope.launch {
            meshService.powerConfig.filterNotNull().collect { pwr ->
                _powerState.value = PowerUiState(
                    isPowerSaving = pwr.isPowerSaving,
                    onBatteryShutdownAfterSecs = pwr.onBatteryShutdownAfterSecs,
                    adcMultiplierOverride = pwr.adcMultiplierOverride,
                    waitBluetoothSecs = pwr.waitBluetoothSecs,
                    sdsSecs = pwr.sdsSecs,
                    lsSecs = pwr.lsSecs,
                    minWakeSecs = pwr.minWakeSecs,
                    shutdownOnPowerLoss = pwr.shutdownOnPowerLoss
                )
            }
        }

        // Observe Network config
        viewModelScope.launch {
            meshService.networkConfig.filterNotNull().collect { net ->
                _networkState.value = NetworkUiState(
                    wifiEnabled = net.wifiEnabled,
                    wifiSsid = net.wifiSsid,
                    wifiPsk = net.wifiPsk,
                    ethEnabled = net.ethEnabled,
                    addressMode = net.addressMode.name,
                    ntpServer = net.ntpServer,
                    rsyslogServer = net.rsyslogServer
                )
            }
        }

        // Observe Display config
        viewModelScope.launch {
            meshService.displayConfig.filterNotNull().collect { dsp ->
                _displayState.value = DisplayUiState(
                    screenOnSecs = dsp.screenOnSecs,
                    gpsFormat = dsp.gpsFormat.name,
                    autoScreenCarouselSecs = dsp.autoScreenCarouselSecs,
                    compassNorthTop = dsp.compassNorthTop,
                    flipScreen = dsp.flipScreen,
                    units = dsp.units.name,
                    oled = dsp.oled.name,
                    displaymode = dsp.displaymode.name,
                    headingBold = dsp.headingBold,
                    wakeOnTapOrMotion = dsp.wakeOnTapOrMotion
                )
            }
        }

        // Observe Bluetooth config
        viewModelScope.launch {
            meshService.bluetoothConfig.filterNotNull().collect { bt ->
                _bluetoothState.value = BluetoothUiState(
                    enabled = bt.enabled,
                    mode = bt.mode.name,
                    fixedPin = bt.fixedPin
                )
            }
        }

        // Observe Owner
        viewModelScope.launch {
            meshService.owner.filterNotNull().collect { user ->
                _ownerState.value = OwnerUiState(
                    longName = user.longName,
                    shortName = user.shortName,
                    isLicensed = user.isLicensed
                )
            }
        }

        // Observe Channels
        viewModelScope.launch {
            meshService.channels.collect { chList ->
                _channelsState.value = chList.map { ch ->
                    ChannelUiState(
                        index = ch.index,
                        role = ch.role.name,
                        name = if (ch.hasSettings()) ch.settings.name else "",
                        pskHex = if (ch.hasSettings()) ch.settings.psk.toByteArray().toHex() else "",
                        uplinkEnabled = if (ch.hasSettings()) ch.settings.uplinkEnabled else false,
                        downlinkEnabled = if (ch.hasSettings()) ch.settings.downlinkEnabled else false
                    )
                }
            }
        }
    }

    // ========================  SETTERS  ========================

    // --- Owner ---
    fun setOwnerLongName(name: String) { _ownerState.value = _ownerState.value.copy(longName = name) }
    fun setOwnerShortName(name: String) { _ownerState.value = _ownerState.value.copy(shortName = name.take(4)) }
    fun setOwnerIsLicensed(licensed: Boolean) { _ownerState.value = _ownerState.value.copy(isLicensed = licensed) }

    // --- LoRa ---
    fun setLoraRegion(region: String) { _loraState.value = _loraState.value.copy(region = region) }
    fun setLoraModemPreset(preset: String) { _loraState.value = _loraState.value.copy(modemPreset = preset) }
    fun setLoraUsePreset(v: Boolean) { _loraState.value = _loraState.value.copy(usePreset = v) }
    fun setLoraBandwidth(v: Int) { _loraState.value = _loraState.value.copy(bandwidth = v) }
    fun setLoraSpreadFactor(v: Int) { _loraState.value = _loraState.value.copy(spreadFactor = v) }
    fun setLoraCodingRate(v: Int) { _loraState.value = _loraState.value.copy(codingRate = v) }
    fun setLoraFrequencyOffset(v: Float) { _loraState.value = _loraState.value.copy(frequencyOffset = v) }
    fun setLoraHopLimit(v: Int) { _loraState.value = _loraState.value.copy(hopLimit = v.coerceIn(1, 7)) }
    fun setLoraTxEnabled(v: Boolean) { _loraState.value = _loraState.value.copy(txEnabled = v) }
    fun setLoraTxPower(v: Int) { _loraState.value = _loraState.value.copy(txPower = v) }
    fun setLoraChannelNum(v: Int) { _loraState.value = _loraState.value.copy(channelNum = v) }
    fun setLoraOverrideDutyCycle(v: Boolean) { _loraState.value = _loraState.value.copy(overrideDutyCycle = v) }
    fun setLoraSx126xRxBoostedGain(v: Boolean) { _loraState.value = _loraState.value.copy(sx126xRxBoostedGain = v) }
    fun setLoraOverrideFrequency(v: Float) { _loraState.value = _loraState.value.copy(overrideFrequency = v) }
    fun setLoraIgnoreMqtt(v: Boolean) { _loraState.value = _loraState.value.copy(ignoreMqtt = v) }

    // --- Device ---
    fun setDeviceRole(role: String) { _deviceState.value = _deviceState.value.copy(role = role) }
    fun setDeviceSerialEnabled(v: Boolean) { _deviceState.value = _deviceState.value.copy(serialEnabled = v) }
    fun setDeviceDebugLogEnabled(v: Boolean) { _deviceState.value = _deviceState.value.copy(debugLogEnabled = v) }
    fun setDeviceButtonGpio(v: Int) { _deviceState.value = _deviceState.value.copy(buttonGpio = v) }
    fun setDeviceBuzzerGpio(v: Int) { _deviceState.value = _deviceState.value.copy(buzzerGpio = v) }
    fun setDeviceRebroadcastMode(mode: String) { _deviceState.value = _deviceState.value.copy(rebroadcastMode = mode) }
    fun setDeviceNodeInfoBroadcastSecs(v: Int) { _deviceState.value = _deviceState.value.copy(nodeInfoBroadcastSecs = v) }
    fun setDeviceDoubleTapAsButtonPress(v: Boolean) { _deviceState.value = _deviceState.value.copy(doubleTapAsButtonPress = v) }
    fun setDeviceIsManaged(v: Boolean) { _deviceState.value = _deviceState.value.copy(isManaged = v) }
    fun setDeviceDisableTripleClick(v: Boolean) { _deviceState.value = _deviceState.value.copy(disableTripleClick = v) }

    // --- Position ---
    fun setPositionBroadcastSecs(v: Int) { _positionState.value = _positionState.value.copy(positionBroadcastSecs = v) }
    fun setPositionSmartEnabled(v: Boolean) { _positionState.value = _positionState.value.copy(positionBroadcastSmartEnabled = v) }
    fun setPositionFixed(v: Boolean) { _positionState.value = _positionState.value.copy(fixedPosition = v) }
    fun setPositionGpsEnabled(v: Boolean) { _positionState.value = _positionState.value.copy(gpsEnabled = v) }
    fun setPositionGpsUpdateInterval(v: Int) { _positionState.value = _positionState.value.copy(gpsUpdateInterval = v) }
    fun setPositionGpsMode(mode: String) { _positionState.value = _positionState.value.copy(gpsMode = mode) }
    fun setPositionSmartMinDistance(v: Int) { _positionState.value = _positionState.value.copy(broadcastSmartMinimumDistance = v) }
    fun setPositionSmartMinInterval(v: Int) { _positionState.value = _positionState.value.copy(broadcastSmartMinimumIntervalSecs = v) }

    // --- Power ---
    fun setPowerSaving(v: Boolean) { _powerState.value = _powerState.value.copy(isPowerSaving = v) }
    fun setPowerShutdownAfterSecs(v: Int) { _powerState.value = _powerState.value.copy(onBatteryShutdownAfterSecs = v) }
    fun setPowerAdcMultiplier(v: Float) { _powerState.value = _powerState.value.copy(adcMultiplierOverride = v) }
    fun setPowerWaitBluetoothSecs(v: Int) { _powerState.value = _powerState.value.copy(waitBluetoothSecs = v) }
    fun setPowerSdsSecs(v: Int) { _powerState.value = _powerState.value.copy(sdsSecs = v) }
    fun setPowerLsSecs(v: Int) { _powerState.value = _powerState.value.copy(lsSecs = v) }
    fun setPowerMinWakeSecs(v: Int) { _powerState.value = _powerState.value.copy(minWakeSecs = v) }
    fun setPowerShutdownOnPowerLoss(v: Boolean) { _powerState.value = _powerState.value.copy(shutdownOnPowerLoss = v) }

    // --- Network ---
    fun setNetworkWifiEnabled(v: Boolean) { _networkState.value = _networkState.value.copy(wifiEnabled = v) }
    fun setNetworkWifiSsid(v: String) { _networkState.value = _networkState.value.copy(wifiSsid = v) }
    fun setNetworkWifiPsk(v: String) { _networkState.value = _networkState.value.copy(wifiPsk = v) }
    fun setNetworkEthEnabled(v: Boolean) { _networkState.value = _networkState.value.copy(ethEnabled = v) }
    fun setNetworkAddressMode(mode: String) { _networkState.value = _networkState.value.copy(addressMode = mode) }
    fun setNetworkNtpServer(v: String) { _networkState.value = _networkState.value.copy(ntpServer = v) }
    fun setNetworkRsyslogServer(v: String) { _networkState.value = _networkState.value.copy(rsyslogServer = v) }

    // --- Display ---
    fun setDisplayScreenOnSecs(v: Int) { _displayState.value = _displayState.value.copy(screenOnSecs = v) }
    fun setDisplayGpsFormat(v: String) { _displayState.value = _displayState.value.copy(gpsFormat = v) }
    fun setDisplayAutoCarouselSecs(v: Int) { _displayState.value = _displayState.value.copy(autoScreenCarouselSecs = v) }
    fun setDisplayCompassNorthTop(v: Boolean) { _displayState.value = _displayState.value.copy(compassNorthTop = v) }
    fun setDisplayFlipScreen(v: Boolean) { _displayState.value = _displayState.value.copy(flipScreen = v) }
    fun setDisplayUnits(v: String) { _displayState.value = _displayState.value.copy(units = v) }
    fun setDisplayOled(v: String) { _displayState.value = _displayState.value.copy(oled = v) }
    fun setDisplayMode(v: String) { _displayState.value = _displayState.value.copy(displaymode = v) }
    fun setDisplayHeadingBold(v: Boolean) { _displayState.value = _displayState.value.copy(headingBold = v) }
    fun setDisplayWakeOnTapOrMotion(v: Boolean) { _displayState.value = _displayState.value.copy(wakeOnTapOrMotion = v) }

    // --- Bluetooth ---
    fun setBluetoothEnabled(v: Boolean) { _bluetoothState.value = _bluetoothState.value.copy(enabled = v) }
    fun setBluetoothMode(mode: String) { _bluetoothState.value = _bluetoothState.value.copy(mode = mode) }
    fun setBluetoothFixedPin(v: Int) { _bluetoothState.value = _bluetoothState.value.copy(fixedPin = v) }

    // --- Channel ---
    fun setChannelName(index: Int, name: String) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(name = name) else it
        }
    }
    fun setChannelPskHex(index: Int, hex: String) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(pskHex = hex) else it
        }
    }
    fun setChannelUplink(index: Int, v: Boolean) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(uplinkEnabled = v) else it
        }
    }
    fun setChannelDownlink(index: Int, v: Boolean) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(downlinkEnabled = v) else it
        }
    }

    // --- Voice ---
    fun setVoiceBitrate(bitrate: AmrNbBitrate) {
        voiceConfig.value = voiceConfig.value.copy(bitrate = bitrate)
    }
    fun setMaxDuration(seconds: Int) {
        voiceConfig.value = voiceConfig.value.copy(maxDurationSeconds = seconds.coerceIn(1, 60))
    }
    fun setChunkTimeout(seconds: Int) {
        voiceConfig.value = voiceConfig.value.copy(chunkTimeoutSeconds = seconds.coerceIn(5, 120))
    }
    fun setPartialPlayOnTimeout(enabled: Boolean) {
        voiceConfig.value = voiceConfig.value.copy(partialPlayOnTimeout = enabled)
    }

    // ========================  APPLY METHODS  ========================

    fun applyOwner() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _ownerState.value
        val user = MeshProtos.User.newBuilder()
            .setLongName(s.longName)
            .setShortName(s.shortName)
            .setIsLicensed(s.isLicensed)
            .build()
        val ok = meshService.writeOwner(user)
        _configStatus.value = if (ok) "Owner config sent" else "Failed to send owner config"
    }

    fun applyLoraConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _loraState.value
        val lora = MeshProtos.Config.LoRaConfig.newBuilder()
            .setUsePreset(s.usePreset)
            .setModemPreset(MeshProtos.Config.LoRaConfig.ModemPreset.valueOf(s.modemPreset))
            .setBandwidth(s.bandwidth)
            .setSpreadFactor(s.spreadFactor)
            .setCodingRate(s.codingRate)
            .setFrequencyOffset(s.frequencyOffset)
            .setRegion(MeshProtos.Config.LoRaConfig.RegionCode.valueOf(s.region))
            .setHopLimit(s.hopLimit)
            .setTxEnabled(s.txEnabled)
            .setTxPower(s.txPower)
            .setChannelNum(s.channelNum)
            .setOverrideDutyCycle(s.overrideDutyCycle)
            .setSx126XRxBoostedGain(s.sx126xRxBoostedGain)
            .setOverrideFrequency(s.overrideFrequency)
            .setIgnoreMqtt(s.ignoreMqtt)
            .build()
        val config = MeshProtos.Config.newBuilder().setLora(lora).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "LoRa config sent" else "Failed to send LoRa config"
    }

    fun applyDeviceConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _deviceState.value
        val dev = MeshProtos.Config.DeviceConfig.newBuilder()
            .setRole(MeshProtos.Config.DeviceConfig.Role.valueOf(s.role))
            .setSerialEnabled(s.serialEnabled)
            .setDebugLogEnabled(s.debugLogEnabled)
            .setButtonGpio(s.buttonGpio)
            .setBuzzerGpio(s.buzzerGpio)
            .setRebroadcastMode(MeshProtos.Config.DeviceConfig.RebroadcastMode.valueOf(s.rebroadcastMode))
            .setNodeInfoBroadcastSecs(s.nodeInfoBroadcastSecs)
            .setDoubleTapAsButtonPress(s.doubleTapAsButtonPress)
            .setIsManaged(s.isManaged)
            .setDisableTripleClick(s.disableTripleClick)
            .build()
        val config = MeshProtos.Config.newBuilder().setDevice(dev).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Device config sent" else "Failed to send device config"
    }

    fun applyPositionConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _positionState.value
        val pos = MeshProtos.Config.PositionConfig.newBuilder()
            .setPositionBroadcastSecs(s.positionBroadcastSecs)
            .setPositionBroadcastSmartEnabled(s.positionBroadcastSmartEnabled)
            .setFixedPosition(s.fixedPosition)
            .setGpsEnabled(s.gpsEnabled)
            .setGpsUpdateInterval(s.gpsUpdateInterval)
            .setGpsMode(MeshProtos.Config.PositionConfig.GpsMode.valueOf(s.gpsMode))
            .setBroadcastSmartMinimumDistance(s.broadcastSmartMinimumDistance)
            .setBroadcastSmartMinimumIntervalSecs(s.broadcastSmartMinimumIntervalSecs)
            .build()
        val config = MeshProtos.Config.newBuilder().setPosition(pos).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Position config sent" else "Failed to send position config"
    }

    fun applyPowerConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _powerState.value
        val pwr = MeshProtos.Config.PowerConfig.newBuilder()
            .setIsPowerSaving(s.isPowerSaving)
            .setOnBatteryShutdownAfterSecs(s.onBatteryShutdownAfterSecs)
            .setAdcMultiplierOverride(s.adcMultiplierOverride)
            .setWaitBluetoothSecs(s.waitBluetoothSecs)
            .setSdsSecs(s.sdsSecs)
            .setLsSecs(s.lsSecs)
            .setMinWakeSecs(s.minWakeSecs)
            .setShutdownOnPowerLoss(s.shutdownOnPowerLoss)
            .build()
        val config = MeshProtos.Config.newBuilder().setPower(pwr).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Power config sent" else "Failed to send power config"
    }

    fun applyNetworkConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _networkState.value
        val net = MeshProtos.Config.NetworkConfig.newBuilder()
            .setWifiEnabled(s.wifiEnabled)
            .setWifiSsid(s.wifiSsid)
            .setWifiPsk(s.wifiPsk)
            .setEthEnabled(s.ethEnabled)
            .setAddressMode(MeshProtos.Config.NetworkConfig.AddressMode.valueOf(s.addressMode))
            .setNtpServer(s.ntpServer)
            .setRsyslogServer(s.rsyslogServer)
            .build()
        val config = MeshProtos.Config.newBuilder().setNetwork(net).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Network config sent" else "Failed to send network config"
    }

    fun applyDisplayConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _displayState.value
        val dsp = MeshProtos.Config.DisplayConfig.newBuilder()
            .setScreenOnSecs(s.screenOnSecs)
            .setGpsFormat(MeshProtos.Config.DisplayConfig.GpsCoordinateFormat.valueOf(s.gpsFormat))
            .setAutoScreenCarouselSecs(s.autoScreenCarouselSecs)
            .setCompassNorthTop(s.compassNorthTop)
            .setFlipScreen(s.flipScreen)
            .setUnits(MeshProtos.Config.DisplayConfig.DisplayUnits.valueOf(s.units))
            .setOled(MeshProtos.Config.DisplayConfig.OledType.valueOf(s.oled))
            .setDisplaymode(MeshProtos.Config.DisplayConfig.DisplayMode.valueOf(s.displaymode))
            .setHeadingBold(s.headingBold)
            .setWakeOnTapOrMotion(s.wakeOnTapOrMotion)
            .build()
        val config = MeshProtos.Config.newBuilder().setDisplay(dsp).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Display config sent" else "Failed to send display config"
    }

    fun applyBluetoothConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _bluetoothState.value
        val bt = MeshProtos.Config.BluetoothConfig.newBuilder()
            .setEnabled(s.enabled)
            .setMode(MeshProtos.Config.BluetoothConfig.PairingMode.valueOf(s.mode))
            .setFixedPin(s.fixedPin)
            .build()
        val config = MeshProtos.Config.newBuilder().setBluetooth(bt).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Bluetooth config sent" else "Failed to send bluetooth config"
    }

    fun applyChannel(index: Int) {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val chUi = _channelsState.value.find { it.index == index } ?: return
        val settings = MeshProtos.ChannelSettings.newBuilder()
            .setName(chUi.name)
            .setPsk(com.google.protobuf.ByteString.copyFrom(chUi.pskHex.hexToBytes()))
            .setUplinkEnabled(chUi.uplinkEnabled)
            .setDownlinkEnabled(chUi.downlinkEnabled)
            .build()
        val channel = MeshProtos.Channel.newBuilder()
            .setIndex(index)
            .setSettings(settings)
            .setRole(MeshProtos.Channel.Role.valueOf(chUi.role))
            .build()
        val ok = meshService.writeChannel(channel)
        _configStatus.value = if (ok) "Channel $index config sent" else "Failed to send channel config"
    }

    // ========================  ACTIONS  ========================

    fun refreshDeviceConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.refreshConfig()
        _configStatus.value = "Config refresh requested"
    }

    fun rebootDevice() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.rebootDevice(5)
        _configStatus.value = "Reboot command sent (5s)"
    }

    fun factoryReset() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.factoryReset()
        _configStatus.value = "Factory reset command sent"
    }

    fun clearStatus() { _configStatus.value = null }

    // ========================  UTILITIES  ========================

    private fun ByteArray.toHex(): String = joinToString("") { "%02x".format(it) }

    private fun String.hexToBytes(): ByteArray {
        val clean = this.replace(" ", "").replace("0x", "")
        if (clean.isEmpty()) return byteArrayOf()
        return clean.chunked(2).map { it.toInt(16).toByte() }.toByteArray()
    }
}

package re.chasam.voicetastic.ui.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.geeksville.mesh.MeshProtos
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import re.chasam.voicetastic.model.AmrNbBitrate
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.service.MeshServiceManager

/**
 * ViewModel for the settings/configuration screen.
 * Manages Meshtastic device config (all sections), channels, owner, modules, and app voice config.
 * Observes config flows from MeshServiceManager and populates UI state on connection.
 */
class ConfigViewModel(
    private val meshService: MeshServiceManager,
    private val voiceConfig: MutableStateFlow<VoiceConfig>
) : ViewModel() {

    val connectionState: StateFlow<String> = meshService.connectionState
    val myNodeId: StateFlow<String?> = meshService.myNodeId
    val firmwareVersion: StateFlow<String?> = meshService.firmwareVersion

    // --- Status ---
    private val _configStatus = MutableStateFlow<String?>(null)
    val configStatus: StateFlow<String?> = _configStatus.asStateFlow()

    // ========================  OWNER  ========================

    data class OwnerUiState(
        val longName: String = "",
        val shortName: String = "",
        val isLicensed: Boolean = false
    )

    private val _ownerState = MutableStateFlow(OwnerUiState())
    val ownerState: StateFlow<OwnerUiState> = _ownerState.asStateFlow()

    // ========================  LORA  ========================

    data class LoraUiState(
        val region: String = "UNSET",
        val modemPreset: String = "LONG_FAST",
        val usePreset: Boolean = true,
        val bandwidth: Int = 0,
        val spreadFactor: Int = 0,
        val codingRate: Int = 0,
        val frequencyOffset: Float = 0f,
        val hopLimit: Int = 3,
        val txEnabled: Boolean = true,
        val txPower: Int = 0,
        val channelNum: Int = 0,
        val overrideDutyCycle: Boolean = false,
        val sx126xRxBoostedGain: Boolean = false,
        val overrideFrequency: Float = 0f,
        val ignoreMqtt: Boolean = false
    )

    private val _loraState = MutableStateFlow(LoraUiState())
    val loraState: StateFlow<LoraUiState> = _loraState.asStateFlow()

    val regions = listOf(
        "UNSET", "US", "EU_433", "EU_868", "CN", "JP", "ANZ", "KR",
        "TW", "RU", "IN", "NZ_865", "TH", "LORA_24", "UA_433", "UA_868"
    )

    val modemPresets = listOf(
        "LONG_FAST", "LONG_SLOW", "VERY_LONG_SLOW",
        "MEDIUM_SLOW", "MEDIUM_FAST",
        "SHORT_SLOW", "SHORT_FAST", "LONG_MODERATE", "SHORT_TURBO"
    )

    // ========================  DEVICE  ========================

    data class DeviceUiState(
        val role: String = "CLIENT",
        val serialEnabled: Boolean = false,
        val debugLogEnabled: Boolean = false,
        val buttonGpio: Int = 0,
        val buzzerGpio: Int = 0,
        val rebroadcastMode: String = "ALL",
        val nodeInfoBroadcastSecs: Int = 0,
        val doubleTapAsButtonPress: Boolean = false,
        val isManaged: Boolean = false,
        val disableTripleClick: Boolean = false
    )

    private val _deviceState = MutableStateFlow(DeviceUiState())
    val deviceState: StateFlow<DeviceUiState> = _deviceState.asStateFlow()

    val deviceRoles = listOf(
        "CLIENT", "CLIENT_MUTE", "ROUTER", "ROUTER_CLIENT", "REPEATER",
        "TRACKER", "SENSOR", "TAK", "CLIENT_HIDDEN", "LOST_AND_FOUND", "TAK_TRACKER"
    )

    val rebroadcastModes = listOf("ALL", "ALL_SKIP_DECODING", "LOCAL_ONLY", "KNOWN_ONLY")

    // ========================  POSITION  ========================

    data class PositionUiState(
        val positionBroadcastSecs: Int = 0,
        val positionBroadcastSmartEnabled: Boolean = false,
        val fixedPosition: Boolean = false,
        val gpsEnabled: Boolean = true,
        val gpsUpdateInterval: Int = 0,
        val gpsMode: String = "ENABLED",
        val broadcastSmartMinimumDistance: Int = 0,
        val broadcastSmartMinimumIntervalSecs: Int = 0
    )

    private val _positionState = MutableStateFlow(PositionUiState())
    val positionState: StateFlow<PositionUiState> = _positionState.asStateFlow()

    val gpsModes = listOf("DISABLED", "ENABLED", "NOT_PRESENT")

    // ========================  POWER  ========================

    data class PowerUiState(
        val isPowerSaving: Boolean = false,
        val onBatteryShutdownAfterSecs: Int = 0,
        val adcMultiplierOverride: Float = 0f,
        val waitBluetoothSecs: Int = 0,
        val sdsSecs: Int = 0,
        val lsSecs: Int = 0,
        val minWakeSecs: Int = 0,
        val shutdownOnPowerLoss: Boolean = false
    )

    private val _powerState = MutableStateFlow(PowerUiState())
    val powerState: StateFlow<PowerUiState> = _powerState.asStateFlow()

    // ========================  NETWORK  ========================

    data class NetworkUiState(
        val wifiEnabled: Boolean = false,
        val wifiSsid: String = "",
        val wifiPsk: String = "",
        val ethEnabled: Boolean = false,
        val addressMode: String = "DHCP",
        val ntpServer: String = "",
        val rsyslogServer: String = ""
    )

    private val _networkState = MutableStateFlow(NetworkUiState())
    val networkState: StateFlow<NetworkUiState> = _networkState.asStateFlow()

    val addressModes = listOf("DHCP", "STATIC")

    // ========================  DISPLAY  ========================

    data class DisplayUiState(
        val screenOnSecs: Int = 0,
        val gpsFormat: String = "DEC",
        val autoScreenCarouselSecs: Int = 0,
        val compassNorthTop: Boolean = false,
        val flipScreen: Boolean = false,
        val units: String = "METRIC",
        val oled: String = "OLED_AUTO",
        val displaymode: String = "DEFAULT",
        val headingBold: Boolean = false,
        val wakeOnTapOrMotion: Boolean = false
    )

    private val _displayState = MutableStateFlow(DisplayUiState())
    val displayState: StateFlow<DisplayUiState> = _displayState.asStateFlow()

    val gpsFormats = listOf("DEC", "DMS", "UTM", "MGRS", "OLC", "OSGR")
    val displayUnits = listOf("METRIC", "IMPERIAL")
    val oledTypes = listOf("OLED_AUTO", "OLED_SSD1306", "OLED_SH1106", "OLED_SH1107")
    val displayModes = listOf("DEFAULT", "TWOCOLOR", "INVERTED", "COLOR")

    // ========================  BLUETOOTH  ========================

    data class BluetoothUiState(
        val enabled: Boolean = true,
        val mode: String = "RANDOM_PIN",
        val fixedPin: Int = 0
    )

    private val _bluetoothState = MutableStateFlow(BluetoothUiState())
    val bluetoothState: StateFlow<BluetoothUiState> = _bluetoothState.asStateFlow()

    val pairingModes = listOf("RANDOM_PIN", "FIXED_PIN", "NO_PIN")

    // ========================  CHANNELS  ========================

    data class ChannelUiState(
        val index: Int = 0,
        val role: String = "DISABLED",
        val name: String = "",
        val pskHex: String = "",
        val uplinkEnabled: Boolean = false,
        val downlinkEnabled: Boolean = false
    )

    private val _channelsState = MutableStateFlow<List<ChannelUiState>>(emptyList())
    val channelsState: StateFlow<List<ChannelUiState>> = _channelsState.asStateFlow()

    val channelRoles = listOf("DISABLED", "PRIMARY", "SECONDARY")

    // ========================  VOICE CONFIG  ========================

    val currentVoiceConfig: StateFlow<VoiceConfig> = voiceConfig.asStateFlow()

    // ========================  INIT — FLOW COLLECTION  ========================

    init {
        // Observe LoRa config from device
        viewModelScope.launch {
            meshService.radioConfig.filterNotNull().collect { lora ->
                val regionName = lora.region.let {
                    if (it == MeshProtos.Config.LoRaConfig.RegionCode.UNRECOGNIZED) "UNSET" else it.name
                }
                val presetName = lora.modemPreset.let {
                    if (it == MeshProtos.Config.LoRaConfig.ModemPreset.UNRECOGNIZED) "LONG_FAST" else it.name
                }
                _loraState.value = LoraUiState(
                    region = regionName,
                    modemPreset = presetName,
                    usePreset = lora.usePreset,
                    bandwidth = lora.bandwidth,
                    spreadFactor = lora.spreadFactor,
                    codingRate = lora.codingRate,
                    frequencyOffset = lora.frequencyOffset,
                    hopLimit = lora.hopLimit,
                    txEnabled = lora.txEnabled,
                    txPower = lora.txPower,
                    channelNum = lora.channelNum,
                    overrideDutyCycle = lora.overrideDutyCycle,
                    sx126xRxBoostedGain = lora.sx126XRxBoostedGain,
                    overrideFrequency = lora.overrideFrequency,
                    ignoreMqtt = lora.ignoreMqtt
                )
            }
        }

        // Observe Device config
        viewModelScope.launch {
            meshService.deviceConfig.filterNotNull().collect { dev ->
                val roleName = dev.role.let {
                    if (it == MeshProtos.Config.DeviceConfig.Role.UNRECOGNIZED) "CLIENT" else it.name
                }
                val rebroadcastName = dev.rebroadcastMode.let {
                    if (it == MeshProtos.Config.DeviceConfig.RebroadcastMode.UNRECOGNIZED) "ALL" else it.name
                }
                _deviceState.value = DeviceUiState(
                    role = roleName,
                    serialEnabled = dev.serialEnabled,
                    debugLogEnabled = dev.debugLogEnabled,
                    buttonGpio = dev.buttonGpio,
                    buzzerGpio = dev.buzzerGpio,
                    rebroadcastMode = rebroadcastName,
                    nodeInfoBroadcastSecs = dev.nodeInfoBroadcastSecs,
                    doubleTapAsButtonPress = dev.doubleTapAsButtonPress,
                    isManaged = dev.isManaged,
                    disableTripleClick = dev.disableTripleClick
                )
            }
        }

        // Observe Position config
        viewModelScope.launch {
            meshService.positionConfig.filterNotNull().collect { pos ->
                _positionState.value = PositionUiState(
                    positionBroadcastSecs = pos.positionBroadcastSecs,
                    positionBroadcastSmartEnabled = pos.positionBroadcastSmartEnabled,
                    fixedPosition = pos.fixedPosition,
                    gpsEnabled = pos.gpsEnabled,
                    gpsUpdateInterval = pos.gpsUpdateInterval,
                    gpsMode = pos.gpsMode.name,
                    broadcastSmartMinimumDistance = pos.broadcastSmartMinimumDistance,
                    broadcastSmartMinimumIntervalSecs = pos.broadcastSmartMinimumIntervalSecs
                )
            }
        }

        // Observe Power config
        viewModelScope.launch {
            meshService.powerConfig.filterNotNull().collect { pwr ->
                _powerState.value = PowerUiState(
                    isPowerSaving = pwr.isPowerSaving,
                    onBatteryShutdownAfterSecs = pwr.onBatteryShutdownAfterSecs,
                    adcMultiplierOverride = pwr.adcMultiplierOverride,
                    waitBluetoothSecs = pwr.waitBluetoothSecs,
                    sdsSecs = pwr.sdsSecs,
                    lsSecs = pwr.lsSecs,
                    minWakeSecs = pwr.minWakeSecs,
                    shutdownOnPowerLoss = pwr.shutdownOnPowerLoss
                )
            }
        }

        // Observe Network config
        viewModelScope.launch {
            meshService.networkConfig.filterNotNull().collect { net ->
                _networkState.value = NetworkUiState(
                    wifiEnabled = net.wifiEnabled,
                    wifiSsid = net.wifiSsid,
                    wifiPsk = net.wifiPsk,
                    ethEnabled = net.ethEnabled,
                    addressMode = net.addressMode.name,
                    ntpServer = net.ntpServer,
                    rsyslogServer = net.rsyslogServer
                )
            }
        }

        // Observe Display config
        viewModelScope.launch {
            meshService.displayConfig.filterNotNull().collect { dsp ->
                _displayState.value = DisplayUiState(
                    screenOnSecs = dsp.screenOnSecs,
                    gpsFormat = dsp.gpsFormat.name,
                    autoScreenCarouselSecs = dsp.autoScreenCarouselSecs,
                    compassNorthTop = dsp.compassNorthTop,
                    flipScreen = dsp.flipScreen,
                    units = dsp.units.name,
                    oled = dsp.oled.name,
                    displaymode = dsp.displaymode.name,
                    headingBold = dsp.headingBold,
                    wakeOnTapOrMotion = dsp.wakeOnTapOrMotion
                )
            }
        }

        // Observe Bluetooth config
        viewModelScope.launch {
            meshService.bluetoothConfig.filterNotNull().collect { bt ->
                _bluetoothState.value = BluetoothUiState(
                    enabled = bt.enabled,
                    mode = bt.mode.name,
                    fixedPin = bt.fixedPin
                )
            }
        }

        // Observe Owner
        viewModelScope.launch {
            meshService.owner.filterNotNull().collect { user ->
                _ownerState.value = OwnerUiState(
                    longName = user.longName,
                    shortName = user.shortName,
                    isLicensed = user.isLicensed
                )
            }
        }

        // Observe Channels
        viewModelScope.launch {
            meshService.channels.collect { chList ->
                _channelsState.value = chList.map { ch ->
                    ChannelUiState(
                        index = ch.index,
                        role = ch.role.name,
                        name = if (ch.hasSettings()) ch.settings.name else "",
                        pskHex = if (ch.hasSettings()) ch.settings.psk.toByteArray().toHex() else "",
                        uplinkEnabled = if (ch.hasSettings()) ch.settings.uplinkEnabled else false,
                        downlinkEnabled = if (ch.hasSettings()) ch.settings.downlinkEnabled else false
                    )
                }
            }
        }
    }

    // ========================  SETTERS  ========================

    // --- Owner ---
    fun setOwnerLongName(name: String) { _ownerState.value = _ownerState.value.copy(longName = name) }
    fun setOwnerShortName(name: String) { _ownerState.value = _ownerState.value.copy(shortName = name.take(4)) }
    fun setOwnerIsLicensed(licensed: Boolean) { _ownerState.value = _ownerState.value.copy(isLicensed = licensed) }

    // --- LoRa ---
    fun setLoraRegion(region: String) { _loraState.value = _loraState.value.copy(region = region) }
    fun setLoraModemPreset(preset: String) { _loraState.value = _loraState.value.copy(modemPreset = preset) }
    fun setLoraUsePreset(v: Boolean) { _loraState.value = _loraState.value.copy(usePreset = v) }
    fun setLoraBandwidth(v: Int) { _loraState.value = _loraState.value.copy(bandwidth = v) }
    fun setLoraSpreadFactor(v: Int) { _loraState.value = _loraState.value.copy(spreadFactor = v) }
    fun setLoraCodingRate(v: Int) { _loraState.value = _loraState.value.copy(codingRate = v) }
    fun setLoraFrequencyOffset(v: Float) { _loraState.value = _loraState.value.copy(frequencyOffset = v) }
    fun setLoraHopLimit(v: Int) { _loraState.value = _loraState.value.copy(hopLimit = v.coerceIn(1, 7)) }
    fun setLoraTxEnabled(v: Boolean) { _loraState.value = _loraState.value.copy(txEnabled = v) }
    fun setLoraTxPower(v: Int) { _loraState.value = _loraState.value.copy(txPower = v) }
    fun setLoraChannelNum(v: Int) { _loraState.value = _loraState.value.copy(channelNum = v) }
    fun setLoraOverrideDutyCycle(v: Boolean) { _loraState.value = _loraState.value.copy(overrideDutyCycle = v) }
    fun setLoraSx126xRxBoostedGain(v: Boolean) { _loraState.value = _loraState.value.copy(sx126xRxBoostedGain = v) }
    fun setLoraOverrideFrequency(v: Float) { _loraState.value = _loraState.value.copy(overrideFrequency = v) }
    fun setLoraIgnoreMqtt(v: Boolean) { _loraState.value = _loraState.value.copy(ignoreMqtt = v) }

    // --- Device ---
    fun setDeviceRole(role: String) { _deviceState.value = _deviceState.value.copy(role = role) }
    fun setDeviceSerialEnabled(v: Boolean) { _deviceState.value = _deviceState.value.copy(serialEnabled = v) }
    fun setDeviceDebugLogEnabled(v: Boolean) { _deviceState.value = _deviceState.value.copy(debugLogEnabled = v) }
    fun setDeviceButtonGpio(v: Int) { _deviceState.value = _deviceState.value.copy(buttonGpio = v) }
    fun setDeviceBuzzerGpio(v: Int) { _deviceState.value = _deviceState.value.copy(buzzerGpio = v) }
    fun setDeviceRebroadcastMode(mode: String) { _deviceState.value = _deviceState.value.copy(rebroadcastMode = mode) }
    fun setDeviceNodeInfoBroadcastSecs(v: Int) { _deviceState.value = _deviceState.value.copy(nodeInfoBroadcastSecs = v) }
    fun setDeviceDoubleTapAsButtonPress(v: Boolean) { _deviceState.value = _deviceState.value.copy(doubleTapAsButtonPress = v) }
    fun setDeviceIsManaged(v: Boolean) { _deviceState.value = _deviceState.value.copy(isManaged = v) }
    fun setDeviceDisableTripleClick(v: Boolean) { _deviceState.value = _deviceState.value.copy(disableTripleClick = v) }

    // --- Position ---
    fun setPositionBroadcastSecs(v: Int) { _positionState.value = _positionState.value.copy(positionBroadcastSecs = v) }
    fun setPositionSmartEnabled(v: Boolean) { _positionState.value = _positionState.value.copy(positionBroadcastSmartEnabled = v) }
    fun setPositionFixed(v: Boolean) { _positionState.value = _positionState.value.copy(fixedPosition = v) }
    fun setPositionGpsEnabled(v: Boolean) { _positionState.value = _positionState.value.copy(gpsEnabled = v) }
    fun setPositionGpsUpdateInterval(v: Int) { _positionState.value = _positionState.value.copy(gpsUpdateInterval = v) }
    fun setPositionGpsMode(mode: String) { _positionState.value = _positionState.value.copy(gpsMode = mode) }
    fun setPositionSmartMinDistance(v: Int) { _positionState.value = _positionState.value.copy(broadcastSmartMinimumDistance = v) }
    fun setPositionSmartMinInterval(v: Int) { _positionState.value = _positionState.value.copy(broadcastSmartMinimumIntervalSecs = v) }

    // --- Power ---
    fun setPowerSaving(v: Boolean) { _powerState.value = _powerState.value.copy(isPowerSaving = v) }
    fun setPowerShutdownAfterSecs(v: Int) { _powerState.value = _powerState.value.copy(onBatteryShutdownAfterSecs = v) }
    fun setPowerAdcMultiplier(v: Float) { _powerState.value = _powerState.value.copy(adcMultiplierOverride = v) }
    fun setPowerWaitBluetoothSecs(v: Int) { _powerState.value = _powerState.value.copy(waitBluetoothSecs = v) }
    fun setPowerSdsSecs(v: Int) { _powerState.value = _powerState.value.copy(sdsSecs = v) }
    fun setPowerLsSecs(v: Int) { _powerState.value = _powerState.value.copy(lsSecs = v) }
    fun setPowerMinWakeSecs(v: Int) { _powerState.value = _powerState.value.copy(minWakeSecs = v) }
    fun setPowerShutdownOnPowerLoss(v: Boolean) { _powerState.value = _powerState.value.copy(shutdownOnPowerLoss = v) }

    // --- Network ---
    fun setNetworkWifiEnabled(v: Boolean) { _networkState.value = _networkState.value.copy(wifiEnabled = v) }
    fun setNetworkWifiSsid(v: String) { _networkState.value = _networkState.value.copy(wifiSsid = v) }
    fun setNetworkWifiPsk(v: String) { _networkState.value = _networkState.value.copy(wifiPsk = v) }
    fun setNetworkEthEnabled(v: Boolean) { _networkState.value = _networkState.value.copy(ethEnabled = v) }
    fun setNetworkAddressMode(mode: String) { _networkState.value = _networkState.value.copy(addressMode = mode) }
    fun setNetworkNtpServer(v: String) { _networkState.value = _networkState.value.copy(ntpServer = v) }
    fun setNetworkRsyslogServer(v: String) { _networkState.value = _networkState.value.copy(rsyslogServer = v) }

    // --- Display ---
    fun setDisplayScreenOnSecs(v: Int) { _displayState.value = _displayState.value.copy(screenOnSecs = v) }
    fun setDisplayGpsFormat(v: String) { _displayState.value = _displayState.value.copy(gpsFormat = v) }
    fun setDisplayAutoCarouselSecs(v: Int) { _displayState.value = _displayState.value.copy(autoScreenCarouselSecs = v) }
    fun setDisplayCompassNorthTop(v: Boolean) { _displayState.value = _displayState.value.copy(compassNorthTop = v) }
    fun setDisplayFlipScreen(v: Boolean) { _displayState.value = _displayState.value.copy(flipScreen = v) }
    fun setDisplayUnits(v: String) { _displayState.value = _displayState.value.copy(units = v) }
    fun setDisplayOled(v: String) { _displayState.value = _displayState.value.copy(oled = v) }
    fun setDisplayMode(v: String) { _displayState.value = _displayState.value.copy(displaymode = v) }
    fun setDisplayHeadingBold(v: Boolean) { _displayState.value = _displayState.value.copy(headingBold = v) }
    fun setDisplayWakeOnTapOrMotion(v: Boolean) { _displayState.value = _displayState.value.copy(wakeOnTapOrMotion = v) }

    // --- Bluetooth ---
    fun setBluetoothEnabled(v: Boolean) { _bluetoothState.value = _bluetoothState.value.copy(enabled = v) }
    fun setBluetoothMode(mode: String) { _bluetoothState.value = _bluetoothState.value.copy(mode = mode) }
    fun setBluetoothFixedPin(v: Int) { _bluetoothState.value = _bluetoothState.value.copy(fixedPin = v) }

    // --- Channel ---
    fun setChannelName(index: Int, name: String) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(name = name) else it
        }
    }
    fun setChannelPskHex(index: Int, hex: String) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(pskHex = hex) else it
        }
    }
    fun setChannelUplink(index: Int, v: Boolean) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(uplinkEnabled = v) else it
        }
    }
    fun setChannelDownlink(index: Int, v: Boolean) {
        _channelsState.value = _channelsState.value.map {
            if (it.index == index) it.copy(downlinkEnabled = v) else it
        }
    }

    // --- Voice ---
    fun setVoiceBitrate(bitrate: AmrNbBitrate) {
        voiceConfig.value = voiceConfig.value.copy(bitrate = bitrate)
    }
    fun setMaxDuration(seconds: Int) {
        voiceConfig.value = voiceConfig.value.copy(maxDurationSeconds = seconds.coerceIn(1, 60))
    }
    fun setChunkTimeout(seconds: Int) {
        voiceConfig.value = voiceConfig.value.copy(chunkTimeoutSeconds = seconds.coerceIn(5, 120))
    }
    fun setPartialPlayOnTimeout(enabled: Boolean) {
        voiceConfig.value = voiceConfig.value.copy(partialPlayOnTimeout = enabled)
    }

    // ========================  APPLY METHODS  ========================

    fun applyOwner() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _ownerState.value
        val user = MeshProtos.User.newBuilder()
            .setLongName(s.longName)
            .setShortName(s.shortName)
            .setIsLicensed(s.isLicensed)
            .build()
        val ok = meshService.writeOwner(user)
        _configStatus.value = if (ok) "Owner config sent" else "Failed to send owner config"
    }

    fun applyLoraConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _loraState.value
        val lora = MeshProtos.Config.LoRaConfig.newBuilder()
            .setUsePreset(s.usePreset)
            .setModemPreset(MeshProtos.Config.LoRaConfig.ModemPreset.valueOf(s.modemPreset))
            .setBandwidth(s.bandwidth)
            .setSpreadFactor(s.spreadFactor)
            .setCodingRate(s.codingRate)
            .setFrequencyOffset(s.frequencyOffset)
            .setRegion(MeshProtos.Config.LoRaConfig.RegionCode.valueOf(s.region))
            .setHopLimit(s.hopLimit)
            .setTxEnabled(s.txEnabled)
            .setTxPower(s.txPower)
            .setChannelNum(s.channelNum)
            .setOverrideDutyCycle(s.overrideDutyCycle)
            .setSx126XRxBoostedGain(s.sx126xRxBoostedGain)
            .setOverrideFrequency(s.overrideFrequency)
            .setIgnoreMqtt(s.ignoreMqtt)
            .build()
        val config = MeshProtos.Config.newBuilder().setLora(lora).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "LoRa config sent" else "Failed to send LoRa config"
    }

    fun applyDeviceConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _deviceState.value
        val dev = MeshProtos.Config.DeviceConfig.newBuilder()
            .setRole(MeshProtos.Config.DeviceConfig.Role.valueOf(s.role))
            .setSerialEnabled(s.serialEnabled)
            .setDebugLogEnabled(s.debugLogEnabled)
            .setButtonGpio(s.buttonGpio)
            .setBuzzerGpio(s.buzzerGpio)
            .setRebroadcastMode(MeshProtos.Config.DeviceConfig.RebroadcastMode.valueOf(s.rebroadcastMode))
            .setNodeInfoBroadcastSecs(s.nodeInfoBroadcastSecs)
            .setDoubleTapAsButtonPress(s.doubleTapAsButtonPress)
            .setIsManaged(s.isManaged)
            .setDisableTripleClick(s.disableTripleClick)
            .build()
        val config = MeshProtos.Config.newBuilder().setDevice(dev).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Device config sent" else "Failed to send device config"
    }

    fun applyPositionConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _positionState.value
        val pos = MeshProtos.Config.PositionConfig.newBuilder()
            .setPositionBroadcastSecs(s.positionBroadcastSecs)
            .setPositionBroadcastSmartEnabled(s.positionBroadcastSmartEnabled)
            .setFixedPosition(s.fixedPosition)
            .setGpsEnabled(s.gpsEnabled)
            .setGpsUpdateInterval(s.gpsUpdateInterval)
            .setGpsMode(MeshProtos.Config.PositionConfig.GpsMode.valueOf(s.gpsMode))
            .setBroadcastSmartMinimumDistance(s.broadcastSmartMinimumDistance)
            .setBroadcastSmartMinimumIntervalSecs(s.broadcastSmartMinimumIntervalSecs)
            .build()
        val config = MeshProtos.Config.newBuilder().setPosition(pos).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Position config sent" else "Failed to send position config"
    }

    fun applyPowerConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _powerState.value
        val pwr = MeshProtos.Config.PowerConfig.newBuilder()
            .setIsPowerSaving(s.isPowerSaving)
            .setOnBatteryShutdownAfterSecs(s.onBatteryShutdownAfterSecs)
            .setAdcMultiplierOverride(s.adcMultiplierOverride)
            .setWaitBluetoothSecs(s.waitBluetoothSecs)
            .setSdsSecs(s.sdsSecs)
            .setLsSecs(s.lsSecs)
            .setMinWakeSecs(s.minWakeSecs)
            .setShutdownOnPowerLoss(s.shutdownOnPowerLoss)
            .build()
        val config = MeshProtos.Config.newBuilder().setPower(pwr).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Power config sent" else "Failed to send power config"
    }

    fun applyNetworkConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _networkState.value
        val net = MeshProtos.Config.NetworkConfig.newBuilder()
            .setWifiEnabled(s.wifiEnabled)
            .setWifiSsid(s.wifiSsid)
            .setWifiPsk(s.wifiPsk)
            .setEthEnabled(s.ethEnabled)
            .setAddressMode(MeshProtos.Config.NetworkConfig.AddressMode.valueOf(s.addressMode))
            .setNtpServer(s.ntpServer)
            .setRsyslogServer(s.rsyslogServer)
            .build()
        val config = MeshProtos.Config.newBuilder().setNetwork(net).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Network config sent" else "Failed to send network config"
    }

    fun applyDisplayConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _displayState.value
        val dsp = MeshProtos.Config.DisplayConfig.newBuilder()
            .setScreenOnSecs(s.screenOnSecs)
            .setGpsFormat(MeshProtos.Config.DisplayConfig.GpsCoordinateFormat.valueOf(s.gpsFormat))
            .setAutoScreenCarouselSecs(s.autoScreenCarouselSecs)
            .setCompassNorthTop(s.compassNorthTop)
            .setFlipScreen(s.flipScreen)
            .setUnits(MeshProtos.Config.DisplayConfig.DisplayUnits.valueOf(s.units))
            .setOled(MeshProtos.Config.DisplayConfig.OledType.valueOf(s.oled))
            .setDisplaymode(MeshProtos.Config.DisplayConfig.DisplayMode.valueOf(s.displaymode))
            .setHeadingBold(s.headingBold)
            .setWakeOnTapOrMotion(s.wakeOnTapOrMotion)
            .build()
        val config = MeshProtos.Config.newBuilder().setDisplay(dsp).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Display config sent" else "Failed to send display config"
    }

    fun applyBluetoothConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val s = _bluetoothState.value
        val bt = MeshProtos.Config.BluetoothConfig.newBuilder()
            .setEnabled(s.enabled)
            .setMode(MeshProtos.Config.BluetoothConfig.PairingMode.valueOf(s.mode))
            .setFixedPin(s.fixedPin)
            .build()
        val config = MeshProtos.Config.newBuilder().setBluetooth(bt).build()
        val ok = meshService.writeConfig(config)
        _configStatus.value = if (ok) "Bluetooth config sent" else "Failed to send bluetooth config"
    }

    fun applyChannel(index: Int) {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        val chUi = _channelsState.value.find { it.index == index } ?: return
        val settings = MeshProtos.ChannelSettings.newBuilder()
            .setName(chUi.name)
            .setPsk(com.google.protobuf.ByteString.copyFrom(chUi.pskHex.hexToBytes()))
            .setUplinkEnabled(chUi.uplinkEnabled)
            .setDownlinkEnabled(chUi.downlinkEnabled)
            .build()
        val channel = MeshProtos.Channel.newBuilder()
            .setIndex(index)
            .setSettings(settings)
            .setRole(MeshProtos.Channel.Role.valueOf(chUi.role))
            .build()
        val ok = meshService.writeChannel(channel)
        _configStatus.value = if (ok) "Channel $index config sent" else "Failed to send channel config"
    }

    // ========================  ACTIONS  ========================

    fun refreshDeviceConfig() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.refreshConfig()
        _configStatus.value = "Config refresh requested"
    }

    fun rebootDevice() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.rebootDevice(5)
        _configStatus.value = "Reboot command sent (5s)"
    }

    fun factoryReset() {
        if (!meshService.isConnected) { _configStatus.value = "Not connected"; return }
        meshService.factoryReset()
        _configStatus.value = "Factory reset command sent"
    }

    fun clearStatus() { _configStatus.value = null }

    // ========================  UTILITIES  ========================

    private fun ByteArray.toHex(): String = joinToString("") { "%02x".format(it) }

    private fun String.hexToBytes(): ByteArray {
        val clean = this.replace(" ", "").replace("0x", "")
        if (clean.isEmpty()) return byteArrayOf()
        return clean.chunked(2).map { it.toInt(16).toByte() }.toByteArray()
    }
}

package re.chasam.voicetastic.service

import android.annotation.SuppressLint
import android.bluetooth.*
import android.bluetooth.le.ScanCallback
import android.bluetooth.le.ScanFilter
import android.bluetooth.le.ScanResult
import android.bluetooth.le.ScanSettings
import android.content.Context
import android.os.ParcelUuid
import android.util.Log
import com.geeksville.mesh.MeshProtos
import com.geeksville.mesh.Portnums.PortNum
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import re.chasam.voicetastic.model.MeshNode
import java.util.concurrent.ConcurrentLinkedQueue

/**
 * Manages direct BLE connection to a Meshtastic device.
 * No Meshtastic Android app required.
 */
class MeshServiceManager(private val context: Context) {

    companion object {
        private const val TAG = "MeshServiceManager"
        private const val MTU_SIZE = 512
        private const val POLL_INTERVAL_MS = 1000L
    }

    data class IncomingText(val from: String, val to: String, val text: String, val channel: Int = 0, val timestamp: Long = System.currentTimeMillis())
    data class IncomingData(val from: String, val to: String, val portNum: Int, val payload: ByteArray, val channel: Int = 0, val timestamp: Long = System.currentTimeMillis())

    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val bleMutex = Mutex()  // Single mutex for all BLE GATT operations (read + write)

    private var bluetoothGatt: BluetoothGatt? = null
    private var toRadioChar: BluetoothGattCharacteristic? = null
    private var fromRadioChar: BluetoothGattCharacteristic? = null

    private var myNodeNum: Int = 0

    // Queue for pending read results
    private val readResultQueue = ConcurrentLinkedQueue<ByteArray?>()
    private val readSemaphore = java.util.concurrent.Semaphore(0)
    private val writeSemaphore = java.util.concurrent.Semaphore(0)
    private val descriptorSemaphore = java.util.concurrent.Semaphore(0)

    // --- Public state flows ---
    private val _connectionState = MutableStateFlow("DISCONNECTED")
    val connectionState: StateFlow<String> = _connectionState.asStateFlow()

    private val _nodes = MutableStateFlow<List<MeshNode>>(emptyList())
    val nodes: StateFlow<List<MeshNode>> = _nodes.asStateFlow()

    private val _incomingTextMessages = MutableSharedFlow<IncomingText>(extraBufferCapacity = 64)
    val incomingTextMessages: SharedFlow<IncomingText> = _incomingTextMessages.asSharedFlow()

    private val _incomingDataMessages = MutableSharedFlow<IncomingData>(extraBufferCapacity = 64)
    val incomingDataMessages: SharedFlow<IncomingData> = _incomingDataMessages.asSharedFlow()

    private val _myNodeId = MutableStateFlow<String?>(null)
    val myNodeId: StateFlow<String?> = _myNodeId.asStateFlow()

    private val _firmwareVersion = MutableStateFlow<String?>(null)
    val firmwareVersion: StateFlow<String?> = _firmwareVersion.asStateFlow()

    private val _discoveredDevices = MutableStateFlow<List<BluetoothDevice>>(emptyList())
    val discoveredDevices: StateFlow<List<BluetoothDevice>> = _discoveredDevices.asStateFlow()

    private val _isScanning = MutableStateFlow(false)
    val isScanning: StateFlow<Boolean> = _isScanning.asStateFlow()

    // --- Per-section config flows ---
    private val _radioConfig = MutableStateFlow<MeshProtos.Config.LoRaConfig?>(null)
    val radioConfig: StateFlow<MeshProtos.Config.LoRaConfig?> = _radioConfig.asStateFlow()

    private val _deviceConfig = MutableStateFlow<MeshProtos.Config.DeviceConfig?>(null)
    val deviceConfig: StateFlow<MeshProtos.Config.DeviceConfig?> = _deviceConfig.asStateFlow()

    private val _positionConfig = MutableStateFlow<MeshProtos.Config.PositionConfig?>(null)
    val positionConfig: StateFlow<MeshProtos.Config.PositionConfig?> = _positionConfig.asStateFlow()

    private val _powerConfig = MutableStateFlow<MeshProtos.Config.PowerConfig?>(null)
    val powerConfig: StateFlow<MeshProtos.Config.PowerConfig?> = _powerConfig.asStateFlow()

    private val _networkConfig = MutableStateFlow<MeshProtos.Config.NetworkConfig?>(null)
    val networkConfig: StateFlow<MeshProtos.Config.NetworkConfig?> = _networkConfig.asStateFlow()

    private val _displayConfig = MutableStateFlow<MeshProtos.Config.DisplayConfig?>(null)
    val displayConfig: StateFlow<MeshProtos.Config.DisplayConfig?> = _displayConfig.asStateFlow()

    private val _bluetoothConfig = MutableStateFlow<MeshProtos.Config.BluetoothConfig?>(null)
    val bluetoothConfig: StateFlow<MeshProtos.Config.BluetoothConfig?> = _bluetoothConfig.asStateFlow()

    private val _channels = MutableStateFlow<List<MeshProtos.Channel>>(emptyList())
    val channels: StateFlow<List<MeshProtos.Channel>> = _channels.asStateFlow()

    private val _owner = MutableStateFlow<MeshProtos.User?>(null)
    val owner: StateFlow<MeshProtos.User?> = _owner.asStateFlow()

    private val _moduleConfigs = MutableStateFlow<Map<String, MeshProtos.ModuleConfig>>(emptyMap())
    val moduleConfigs: StateFlow<Map<String, MeshProtos.ModuleConfig>> = _moduleConfigs.asStateFlow()

    private val nodeMap = mutableMapOf<Int, MeshNode>()

    val isConnected: Boolean
        get() = _connectionState.value == "CONNECTED"

    // ==========  BLE SCANNING  ==========

    private val scanCallback = object : ScanCallback() {
        @SuppressLint("MissingPermission")
        override fun onScanResult(callbackType: Int, result: ScanResult) {
            val device = result.device
            val current = _discoveredDevices.value.toMutableList()
            if (current.none { it.address == device.address }) {
                current.add(device)
                _discoveredDevices.value = current
                Log.i(TAG, "Found Meshtastic device: ${device.name ?: device.address}")
            }
        }

        override fun onScanFailed(errorCode: Int) {
            Log.e(TAG, "BLE scan failed: $errorCode")
            _isScanning.value = false
        }
    }

    @SuppressLint("MissingPermission")
    fun startScan() {
        val adapter = BluetoothAdapter.getDefaultAdapter() ?: return
        val scanner = adapter.bluetoothLeScanner ?: return

        _discoveredDevices.value = emptyList()
        _isScanning.value = true

        val filter = ScanFilter.Builder()
            .setServiceUuid(ParcelUuid(MeshtasticBle.SERVICE_UUID))
            .build()
        val settings = ScanSettings.Builder()
            .setScanMode(ScanSettings.SCAN_MODE_LOW_LATENCY)
            .build()

        scanner.startScan(listOf(filter), settings, scanCallback)

        scope.launch {
            delay(15_000)
            stopScan()
        }
    }

    @SuppressLint("MissingPermission")
    fun stopScan() {
        try {
            BluetoothAdapter.getDefaultAdapter()?.bluetoothLeScanner?.stopScan(scanCallback)
        } catch (_: Exception) {}
        _isScanning.value = false
    }

    // ==========  BLE CONNECTION  ==========

    @SuppressLint("MissingPermission")
    fun connect(device: BluetoothDevice) {
        stopScan()
        _connectionState.value = "CONNECTING"
        Log.i(TAG, "Connecting to ${device.name ?: device.address}")
        bluetoothGatt = device.connectGatt(context, false, gattCallback, BluetoothDevice.TRANSPORT_LE)
    }

    fun bind() = startScan()

    @SuppressLint("MissingPermission")
    fun disconnect() {
        stopPolling()
        try { bluetoothGatt?.disconnect() } catch (_: Exception) {}
        try { bluetoothGatt?.close() } catch (_: Exception) {}
        bluetoothGatt = null
        toRadioChar = null
        fromRadioChar = null
        _connectionState.value = "DISCONNECTED"
        myNodeNum = 0
        _myNodeId.value = null
        _firmwareVersion.value = null
        nodeMap.clear()
        _nodes.value = emptyList()
        _radioConfig.value = null
        _deviceConfig.value = null
        _positionConfig.value = null
        _powerConfig.value = null
        _networkConfig.value = null
        _displayConfig.value = null
        _bluetoothConfig.value = null
        _channels.value = emptyList()
        _owner.value = null
        _moduleConfigs.value = emptyMap()
        Log.i(TAG, "Disconnected")
    }

    fun unbind() = disconnect()

    fun destroy() {
        disconnect()
        scope.cancel()
    }

    private var serviceDiscoveryRetries = 0
    private val maxServiceDiscoveryRetries = 3

    /**
     * Clears the BLE GATT cache via reflection.
     * This is a standard Android workaround for stale GATT service data.
     */
    @SuppressLint("MissingPermission")
    private fun refreshGattCache(gatt: BluetoothGatt): Boolean {
        return try {
            val method = gatt.javaClass.getMethod("refresh")
            method.invoke(gatt) as? Boolean ?: false
        } catch (e: Exception) {
            Log.w(TAG, "Failed to refresh GATT cache", e)
            false
        }
    }

    @SuppressLint("MissingPermission")
    private val gattCallback = object : BluetoothGattCallback() {

        override fun onConnectionStateChange(gatt: BluetoothGatt, status: Int, newState: Int) {
            when (newState) {
                BluetoothGatt.STATE_CONNECTED -> {
                    Log.i(TAG, "GATT connected, refreshing cache and requesting MTU")
                    serviceDiscoveryRetries = 0
                    refreshGattCache(gatt)
                    // Small delay to let the cache clear take effect
                    scope.launch {
                        delay(600)
                        gatt.requestMtu(MTU_SIZE)
                    }
                }
                BluetoothGatt.STATE_DISCONNECTED -> {
                    Log.w(TAG, "GATT disconnected (status=$status)")
                    _connectionState.value = "DISCONNECTED"
                }
            }
        }

        override fun onMtuChanged(gatt: BluetoothGatt, mtu: Int, status: Int) {
            Log.i(TAG, "MTU changed to $mtu")
            gatt.discoverServices()
        }

        override fun onServicesDiscovered(gatt: BluetoothGatt, status: Int) {
            if (status != BluetoothGatt.GATT_SUCCESS) {
                Log.e(TAG, "Service discovery failed: $status")
                return
            }

            val service = gatt.getService(MeshtasticBle.SERVICE_UUID)
            if (service == null) {
                Log.e(TAG, "Meshtastic BLE service not found")
                scope.launch { disconnect() }
                return
            }

            toRadioChar = service.getCharacteristic(MeshtasticBle.TORADIO_UUID)
            fromRadioChar = service.getCharacteristic(MeshtasticBle.FROMRADIO_UUID)
            val fromNumChar = service.getCharacteristic(MeshtasticBle.FROMNUM_UUID)

            if (toRadioChar == null || fromRadioChar == null) {
                Log.e(TAG, "Missing required BLE characteristics: " +
                    "toRadio=${toRadioChar != null}, fromRadio=${fromRadioChar != null}")

                if (serviceDiscoveryRetries < maxServiceDiscoveryRetries) {
                    serviceDiscoveryRetries++
                    Log.w(TAG, "Retrying service discovery (attempt $serviceDiscoveryRetries/$maxServiceDiscoveryRetries)")
                    scope.launch {
                        delay(1000L * serviceDiscoveryRetries)
                        refreshGattCache(gatt)
                        delay(500)
                        gatt.discoverServices()
                    }
                    return
                }

                Log.e(TAG, "All retries exhausted, disconnecting")
                scope.launch { disconnect() }
                return
            }

            // Enable notifications: prefer FromNum if available (legacy firmware),
            // otherwise subscribe to FromRadio notifications (firmware 2.5+)
            val notifyChar = fromNumChar ?: fromRadioChar!!
            if (fromNumChar != null) {
                Log.i(TAG, "Subscribing to FromNum notifications (legacy mode)")
            } else {
                Log.i(TAG, "FromNum not available, subscribing to FromRadio notifications (firmware 2.5+)")
            }

            gatt.setCharacteristicNotification(notifyChar, true)
            val descriptor = notifyChar.getDescriptor(MeshtasticBle.CCCD_UUID)
            if (descriptor != null) {
                descriptor.value = BluetoothGattDescriptor.ENABLE_NOTIFICATION_VALUE
                gatt.writeDescriptor(descriptor)
            } else {
                // No descriptor, proceed anyway
                onSetupComplete()
            }
        }

        override fun onDescriptorWrite(gatt: BluetoothGatt, descriptor: BluetoothGattDescriptor, status: Int) {
            Log.i(TAG, "Descriptor write status=$status")
            descriptorSemaphore.release()
            onSetupComplete()
        }

        override fun onCharacteristicRead(
            gatt: BluetoothGatt,
            characteristic: BluetoothGattCharacteristic,
            value: ByteArray,
            status: Int
        ) {
            if (status == BluetoothGatt.GATT_SUCCESS && characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                readResultQueue.add(value)
            } else {
                readResultQueue.add(null)
            }
            readSemaphore.release()
        }

        @Deprecated("Deprecated in API 33")
        override fun onCharacteristicRead(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic, status: Int) {
            if (status == BluetoothGatt.GATT_SUCCESS && characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                readResultQueue.add(characteristic.value)
            } else {
                readResultQueue.add(null)
            }
            readSemaphore.release()
        }

        override fun onCharacteristicWrite(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic, status: Int) {
            writeSemaphore.release()
        }

        override fun onCharacteristicChanged(
            gatt: BluetoothGatt,
            characteristic: BluetoothGattCharacteristic,
            value: ByteArray
        ) {
            if (characteristic.uuid == MeshtasticBle.FROMNUM_UUID) {
                // Legacy firmware: FromNum notifies that new data is available
                scope.launch { readAllFromRadio() }
            } else if (characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                // Firmware 2.5+: FromRadio notifies directly with data
                scope.launch {
                    if (value.isNotEmpty()) {
                        try {
                            val fromRadio = MeshProtos.FromRadio.parseFrom(value)
                            handleFromRadio(fromRadio)
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to parse FromRadio notification", e)
                        }
                    }
                    // There may be more queued, read remaining
                    readAllFromRadio()
                }
            }
        }

        @Deprecated("Deprecated in API 33")
        override fun onCharacteristicChanged(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic) {
            if (characteristic.uuid == MeshtasticBle.FROMNUM_UUID) {
                scope.launch { readAllFromRadio() }
            } else if (characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                val value = characteristic.value
                scope.launch {
                    if (value != null && value.isNotEmpty()) {
                        try {
                            val fromRadio = MeshProtos.FromRadio.parseFrom(value)
                            handleFromRadio(fromRadio)
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to parse FromRadio notification", e)
                        }
                    }
                    readAllFromRadio()
                }
            }
        }
    }

    private var pollingJob: Job? = null

    private fun onSetupComplete() {
        _connectionState.value = "CONNECTED"
        Log.i(TAG, "BLE setup complete, requesting config")
        scope.launch {
            delay(300)
            requestConfig()
        }
        startPolling()
    }

    /**
     * Start a periodic polling loop that reads queued messages from the device.
     * This acts as a safety net in case BLE notifications are missed or coalesced.
     */
    private fun startPolling() {
        pollingJob?.cancel()
        pollingJob = scope.launch {
            while (isActive) {
                delay(POLL_INTERVAL_MS)
                if (isConnected) {
                    try {
                        readAllFromRadio()
                    } catch (e: Exception) {
                        Log.w(TAG, "Polling read failed", e)
                    }
                }
            }
        }
    }

    private fun stopPolling() {
        pollingJob?.cancel()
        pollingJob = null
    }

    // ==========  MESHTASTIC PROTOCOL  ==========

    /**
     * Request full device configuration from the connected node.
     * Public so the UI can trigger a re-read.
     */
    fun refreshConfig() {
        if (!isConnected) return
        scope.launch { requestConfig() }
    }

    private suspend fun requestConfig() {
        val configId = (System.currentTimeMillis() % Int.MAX_VALUE).toInt()
        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setWantConfigId(configId)
            .build()
        writeToRadio(toRadio)
        delay(500)
        readAllFromRadio()
    }

    @SuppressLint("MissingPermission")
    private suspend fun readAllFromRadio() {
        val gatt = bluetoothGatt ?: return
        val char = fromRadioChar ?: return

        bleMutex.withLock {
            var attempts = 0
            while (attempts < 100) {
                readSemaphore.drainPermits()
                readResultQueue.clear()

                if (!gatt.readCharacteristic(char)) break

                // Wait for callback
                if (!readSemaphore.tryAcquire(2, java.util.concurrent.TimeUnit.SECONDS)) break

                val data = readResultQueue.poll()
                if (data == null || data.isEmpty()) break

                try {
                    val fromRadio = MeshProtos.FromRadio.parseFrom(data)
                    handleFromRadio(fromRadio)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to parse FromRadio", e)
                }
                attempts++
                delay(50)
            }
        }
    }

    private fun handleFromRadio(fromRadio: MeshProtos.FromRadio) {
        when {
            fromRadio.hasMyInfo() -> {
                val info = fromRadio.myInfo
                myNodeNum = info.myNodeNum
                _myNodeId.value = MeshtasticBle.nodeNumToId(myNodeNum)
                _firmwareVersion.value = info.firmwareVersion
                Log.i(TAG, "My node: ${_myNodeId.value} (fw: ${info.firmwareVersion})")
            }

            fromRadio.hasNodeInfo() -> {
                val ni = fromRadio.nodeInfo
                val node = MeshNode(
                    nodeId = MeshtasticBle.nodeNumToId(ni.num),
                    longName = if (ni.hasUser()) ni.user.longName else "Unknown",
                    shortName = if (ni.hasUser()) ni.user.shortName else "??",
                    lastHeard = ni.lastHeard.toLong(),
                    batteryLevel = if (ni.hasDeviceMetrics()) ni.deviceMetrics.batteryLevel.toInt() else null,
                    snr = if (ni.snr != 0f) ni.snr else null
                )
                nodeMap[ni.num] = node
                _nodes.value = nodeMap.values.toList()

                // If this is our own node, capture the User as owner
                if (ni.num == myNodeNum && ni.hasUser()) {
                    _owner.value = ni.user
                }
            }

            fromRadio.hasPacket() -> handleMeshPacket(fromRadio.packet)

            fromRadio.hasConfig() -> handleConfig(fromRadio.config)

            fromRadio.hasModuleConfig() -> handleModuleConfig(fromRadio.moduleConfig)

            fromRadio.hasChannel() -> {
                val ch = fromRadio.channel
                val current = _channels.value.toMutableList()
                val idx = current.indexOfFirst { it.index == ch.index }
                if (idx >= 0) current[idx] = ch else current.add(ch)
                _channels.value = current
            }

            fromRadio.configCompleteId != 0 -> {
                Log.i(TAG, "Config complete (id=${fromRadio.configCompleteId})")
            }
        }
    }

    private fun handleConfig(config: MeshProtos.Config) {
        when {
            config.hasLora() -> {
                _radioConfig.value = config.lora
                Log.i(TAG, "LoRa config: region=${config.lora.region}, preset=${config.lora.modemPreset}")
            }
            config.hasDevice() -> {
                _deviceConfig.value = config.device
                Log.i(TAG, "Device config: role=${config.device.role}")
            }
            config.hasPosition() -> {
                _positionConfig.value = config.position
                Log.i(TAG, "Position config: gps=${config.position.gpsEnabled}, broadcast=${config.position.positionBroadcastSecs}s")
            }
            config.hasPower() -> {
                _powerConfig.value = config.power
                Log.i(TAG, "Power config: power_saving=${config.power.isPowerSaving}")
            }
            config.hasNetwork() -> {
                _networkConfig.value = config.network
                Log.i(TAG, "Network config: wifi=${config.network.wifiEnabled}")
            }
            config.hasDisplay() -> {
                _displayConfig.value = config.display
                Log.i(TAG, "Display config: screen_on=${config.display.screenOnSecs}s")
            }
            config.hasBluetooth() -> {
                _bluetoothConfig.value = config.bluetooth
                Log.i(TAG, "Bluetooth config: enabled=${config.bluetooth.enabled}, mode=${config.bluetooth.mode}")
            }
        }
    }

    private fun handleModuleConfig(moduleConfig: MeshProtos.ModuleConfig) {
        val key = when {
            moduleConfig.hasMqtt() -> "mqtt"
            moduleConfig.hasSerial() -> "serial"
            moduleConfig.hasExternalNotification() -> "external_notification"
            moduleConfig.hasStoreForward() -> "store_forward"
            moduleConfig.hasRangeTest() -> "range_test"
            moduleConfig.hasTelemetry() -> "telemetry"
            moduleConfig.hasCannedMessage() -> "canned_message"
            moduleConfig.hasAudio() -> "audio"
            moduleConfig.hasRemoteHardware() -> "remote_hardware"
            moduleConfig.hasNeighborInfo() -> "neighbor_info"
            moduleConfig.hasAmbientLighting() -> "ambient_lighting"
            moduleConfig.hasDetectionSensor() -> "detection_sensor"
            moduleConfig.hasPaxcounter() -> "paxcounter"
            else -> return
        }
        val current = _moduleConfigs.value.toMutableMap()
        current[key] = moduleConfig
        _moduleConfigs.value = current
        Log.i(TAG, "Module config received: $key")
    }

    private fun handleMeshPacket(packet: MeshProtos.MeshPacket) {
        if (!packet.hasDecoded()) return

        val data = packet.decoded
        val fromNum = packet.from
        val toNum = packet.getTo()
        val fromId = MeshtasticBle.nodeNumToId(fromNum)
        val toId = if (toNum == MeshtasticBle.BROADCAST_ADDR || toNum == 0) "broadcast"
                   else MeshtasticBle.nodeNumToId(toNum)
        val channel = packet.channel
        Log.d(TAG, "Packet from=$fromNum (${fromId}) to=$toNum (${toId}) ch=$channel")

        when (data.portnum) {
            PortNum.TEXT_MESSAGE_APP -> {
                val text = data.payload.toStringUtf8()
                _incomingTextMessages.tryEmit(IncomingText(from = fromId, to = toId, text = text, channel = channel))
                Log.i(TAG, "Text from $fromId to $toId (ch=$channel): $text")
            }

            PortNum.NODEINFO_APP -> {
                try {
                    val user = MeshProtos.User.parseFrom(data.payload)
                    nodeMap[fromNum] = MeshNode(
                        nodeId = MeshtasticBle.nodeNumToId(fromNum),
                        longName = user.longName,
                        shortName = user.shortName
                    )
                    _nodes.value = nodeMap.values.toList()
                } catch (_: Exception) {}
            }

            PortNum.ADMIN_APP -> {
                // Handle admin responses (e.g. after a get_config_request)
                try {
                    val admin = MeshProtos.AdminMessage.parseFrom(data.payload)
                    handleAdminResponse(admin)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to parse AdminMessage", e)
                }
            }

            else -> {
                _incomingDataMessages.tryEmit(
                    IncomingData(from = fromId, to = toId, portNum = data.portnumValue, payload = data.payload.toByteArray(), channel = channel)
                )
            }
        }
    }

    private fun handleAdminResponse(admin: MeshProtos.AdminMessage) {
        when {
            admin.hasGetConfigResponse() -> handleConfig(admin.getConfigResponse)
            admin.hasGetModuleConfigResponse() -> handleModuleConfig(admin.getModuleConfigResponse)
            admin.hasGetChannelResponse() -> {
                val ch = admin.getChannelResponse
                val current = _channels.value.toMutableList()
                val idx = current.indexOfFirst { it.index == ch.index }
                if (idx >= 0) current[idx] = ch else current.add(ch)
                _channels.value = current
            }
            admin.hasGetOwnerResponse() -> {
                _owner.value = admin.getOwnerResponse
            }
        }
    }

    // ==========  SENDING  ==========

    @SuppressLint("MissingPermission")
    private suspend fun writeToRadio(toRadio: MeshProtos.ToRadio) {
        val gatt = bluetoothGatt ?: return
        val char = toRadioChar ?: return
        val bytes = toRadio.toByteArray()

        bleMutex.withLock {
            writeSemaphore.drainPermits()
            val initiated = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
                gatt.writeCharacteristic(char, bytes, BluetoothGattCharacteristic.WRITE_TYPE_DEFAULT) == BluetoothGatt.GATT_SUCCESS
            } else {
                @Suppress("DEPRECATION")
                char.value = bytes
                @Suppress("DEPRECATION")
                char.writeType = BluetoothGattCharacteristic.WRITE_TYPE_DEFAULT
                @Suppress("DEPRECATION")
                gatt.writeCharacteristic(char)
            }
            if (initiated) {
                if (!writeSemaphore.tryAcquire(2, java.util.concurrent.TimeUnit.SECONDS)) {
                    Log.w(TAG, "Write timeout waiting for callback (${bytes.size} bytes)")
                } else {
                    Log.d(TAG, "ToRadio write success (${bytes.size} bytes)")
                }
            } else {
                Log.e(TAG, "Failed to initiate BLE write ToRadio (${bytes.size} bytes)")
            }
        }
    }

    fun sendText(text: String, destination: String? = null, channel: Int = 0): Boolean {
        if (!isConnected) return false

        val destNum = if (destination != null) {
            MeshtasticBle.nodeIdToNum(destination) ?: run {
                Log.e(TAG, "Invalid destination node ID: $destination")
                return false
            }
        } else {
            MeshtasticBle.BROADCAST_ADDR
        }

        val data = MeshProtos.Data.newBuilder()
            .setPortnum(PortNum.TEXT_MESSAGE_APP)
            .setPayload(com.google.protobuf.ByteString.copyFromUtf8(text))
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(destNum)
            .setChannel(channel)
            .setDecoded(data)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        Log.i(TAG, "Sending text to ${destination ?: "broadcast"} (dest=$destNum): $text")
        return true
    }

    fun sendData(data: ByteArray, portNum: Int, destination: String? = null, channel: Int = 0): Boolean {
        if (!isConnected) return false

        val destNum = if (destination != null) {
            MeshtasticBle.nodeIdToNum(destination) ?: run {
                Log.e(TAG, "Invalid destination node ID: $destination")
                return false
            }
        } else {
            MeshtasticBle.BROADCAST_ADDR
        }

        val meshData = MeshProtos.Data.newBuilder()
            .setPortnumValue(portNum)
            .setPayload(com.google.protobuf.ByteString.copyFrom(data))
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(destNum)
            .setChannel(channel)
            .setDecoded(meshData)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        Log.i(TAG, "Sending data (port=$portNum, ${data.size} bytes) to ${destination ?: "broadcast"}")
        return true
    }

    // ==========  ADMIN CONFIG WRITES (local node only)  ==========

    private fun sendAdminMessage(admin: MeshProtos.AdminMessage): Boolean {
        if (!isConnected || myNodeNum == 0) return false

        val data = MeshProtos.Data.newBuilder()
            .setPortnum(PortNum.ADMIN_APP)
            .setPayload(admin.toByteString())
            .setWantResponse(true)
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(myNodeNum)
            .setDecoded(data)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        return true
    }

    /**
     * Write a Config section (LoRa, Device, Position, Power, Network, Display, Bluetooth)
     * to the local connected device.
     */
    fun writeConfig(config: MeshProtos.Config): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetConfig(config)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write a ModuleConfig section to the local connected device.
     */
    fun writeModuleConfig(moduleConfig: MeshProtos.ModuleConfig): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetModuleConfig(moduleConfig)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write a Channel configuration to the local connected device.
     */
    fun writeChannel(channel: MeshProtos.Channel): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetChannel(channel)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write the User/Owner info to the local connected device.
     */
    fun writeOwner(user: MeshProtos.User): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetOwner(user)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Reboot the device after the specified number of seconds.
     */
    fun rebootDevice(seconds: Int = 5): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setRebootSeconds(seconds)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Factory reset the device.
     */
    fun factoryReset(): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setFactoryReset(true)
            .build()
        return sendAdminMessage(admin)
    }

    // ==========  LEGACY CONFIG ACCESSORS  ==========

    fun getRadioConfig(): ByteArray? = _radioConfig.value?.toByteArray()

    fun setRadioConfig(config: ByteArray): Boolean {
        Log.i(TAG, "setRadioConfig: ${config.size} bytes")
        return isConnected
    }

    fun getChannels(): ByteArray? = null

    fun setChannels(channels: ByteArray): Boolean {
        Log.i(TAG, "setChannels: ${channels.size} bytes")
        return isConnected
    }
}

package re.chasam.voicetastic.service

import android.annotation.SuppressLint
import android.bluetooth.*
import android.bluetooth.le.ScanCallback
import android.bluetooth.le.ScanFilter
import android.bluetooth.le.ScanResult
import android.bluetooth.le.ScanSettings
import android.content.Context
import android.os.ParcelUuid
import android.util.Log
import com.geeksville.mesh.MeshProtos
import com.geeksville.mesh.Portnums.PortNum
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import re.chasam.voicetastic.model.MeshNode
import java.util.concurrent.ConcurrentLinkedQueue

/**
 * Manages direct BLE connection to a Meshtastic device.
 * No Meshtastic Android app required.
 */
class MeshServiceManager(private val context: Context) {

    companion object {
        private const val TAG = "MeshServiceManager"
        private const val MTU_SIZE = 512
        private const val POLL_INTERVAL_MS = 1000L
    }

    data class IncomingText(val from: String, val to: String, val text: String, val channel: Int = 0, val timestamp: Long = System.currentTimeMillis())
    data class IncomingData(val from: String, val to: String, val portNum: Int, val payload: ByteArray, val channel: Int = 0, val timestamp: Long = System.currentTimeMillis())

    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())
    private val bleMutex = Mutex()  // Single mutex for all BLE GATT operations (read + write)

    private var bluetoothGatt: BluetoothGatt? = null
    private var toRadioChar: BluetoothGattCharacteristic? = null
    private var fromRadioChar: BluetoothGattCharacteristic? = null

    private var myNodeNum: Int = 0

    // Queue for pending read results
    private val readResultQueue = ConcurrentLinkedQueue<ByteArray?>()
    private val readSemaphore = java.util.concurrent.Semaphore(0)
    private val writeSemaphore = java.util.concurrent.Semaphore(0)
    private val descriptorSemaphore = java.util.concurrent.Semaphore(0)

    // --- Public state flows ---
    private val _connectionState = MutableStateFlow("DISCONNECTED")
    val connectionState: StateFlow<String> = _connectionState.asStateFlow()

    private val _nodes = MutableStateFlow<List<MeshNode>>(emptyList())
    val nodes: StateFlow<List<MeshNode>> = _nodes.asStateFlow()

    private val _incomingTextMessages = MutableSharedFlow<IncomingText>(extraBufferCapacity = 64)
    val incomingTextMessages: SharedFlow<IncomingText> = _incomingTextMessages.asSharedFlow()

    private val _incomingDataMessages = MutableSharedFlow<IncomingData>(extraBufferCapacity = 64)
    val incomingDataMessages: SharedFlow<IncomingData> = _incomingDataMessages.asSharedFlow()

    private val _myNodeId = MutableStateFlow<String?>(null)
    val myNodeId: StateFlow<String?> = _myNodeId.asStateFlow()

    private val _firmwareVersion = MutableStateFlow<String?>(null)
    val firmwareVersion: StateFlow<String?> = _firmwareVersion.asStateFlow()

    private val _discoveredDevices = MutableStateFlow<List<BluetoothDevice>>(emptyList())
    val discoveredDevices: StateFlow<List<BluetoothDevice>> = _discoveredDevices.asStateFlow()

    private val _isScanning = MutableStateFlow(false)
    val isScanning: StateFlow<Boolean> = _isScanning.asStateFlow()

    // --- Per-section config flows ---
    private val _radioConfig = MutableStateFlow<MeshProtos.Config.LoRaConfig?>(null)
    val radioConfig: StateFlow<MeshProtos.Config.LoRaConfig?> = _radioConfig.asStateFlow()

    private val _deviceConfig = MutableStateFlow<MeshProtos.Config.DeviceConfig?>(null)
    val deviceConfig: StateFlow<MeshProtos.Config.DeviceConfig?> = _deviceConfig.asStateFlow()

    private val _positionConfig = MutableStateFlow<MeshProtos.Config.PositionConfig?>(null)
    val positionConfig: StateFlow<MeshProtos.Config.PositionConfig?> = _positionConfig.asStateFlow()

    private val _powerConfig = MutableStateFlow<MeshProtos.Config.PowerConfig?>(null)
    val powerConfig: StateFlow<MeshProtos.Config.PowerConfig?> = _powerConfig.asStateFlow()

    private val _networkConfig = MutableStateFlow<MeshProtos.Config.NetworkConfig?>(null)
    val networkConfig: StateFlow<MeshProtos.Config.NetworkConfig?> = _networkConfig.asStateFlow()

    private val _displayConfig = MutableStateFlow<MeshProtos.Config.DisplayConfig?>(null)
    val displayConfig: StateFlow<MeshProtos.Config.DisplayConfig?> = _displayConfig.asStateFlow()

    private val _bluetoothConfig = MutableStateFlow<MeshProtos.Config.BluetoothConfig?>(null)
    val bluetoothConfig: StateFlow<MeshProtos.Config.BluetoothConfig?> = _bluetoothConfig.asStateFlow()

    private val _channels = MutableStateFlow<List<MeshProtos.Channel>>(emptyList())
    val channels: StateFlow<List<MeshProtos.Channel>> = _channels.asStateFlow()

    private val _owner = MutableStateFlow<MeshProtos.User?>(null)
    val owner: StateFlow<MeshProtos.User?> = _owner.asStateFlow()

    private val _moduleConfigs = MutableStateFlow<Map<String, MeshProtos.ModuleConfig>>(emptyMap())
    val moduleConfigs: StateFlow<Map<String, MeshProtos.ModuleConfig>> = _moduleConfigs.asStateFlow()

    private val nodeMap = mutableMapOf<Int, MeshNode>()

    val isConnected: Boolean
        get() = _connectionState.value == "CONNECTED"

    // ==========  BLE SCANNING  ==========

    private val scanCallback = object : ScanCallback() {
        @SuppressLint("MissingPermission")
        override fun onScanResult(callbackType: Int, result: ScanResult) {
            val device = result.device
            val current = _discoveredDevices.value.toMutableList()
            if (current.none { it.address == device.address }) {
                current.add(device)
                _discoveredDevices.value = current
                Log.i(TAG, "Found Meshtastic device: ${device.name ?: device.address}")
            }
        }

        override fun onScanFailed(errorCode: Int) {
            Log.e(TAG, "BLE scan failed: $errorCode")
            _isScanning.value = false
        }
    }

    @SuppressLint("MissingPermission")
    fun startScan() {
        val adapter = BluetoothAdapter.getDefaultAdapter() ?: return
        val scanner = adapter.bluetoothLeScanner ?: return

        _discoveredDevices.value = emptyList()
        _isScanning.value = true

        val filter = ScanFilter.Builder()
            .setServiceUuid(ParcelUuid(MeshtasticBle.SERVICE_UUID))
            .build()
        val settings = ScanSettings.Builder()
            .setScanMode(ScanSettings.SCAN_MODE_LOW_LATENCY)
            .build()

        scanner.startScan(listOf(filter), settings, scanCallback)

        scope.launch {
            delay(15_000)
            stopScan()
        }
    }

    @SuppressLint("MissingPermission")
    fun stopScan() {
        try {
            BluetoothAdapter.getDefaultAdapter()?.bluetoothLeScanner?.stopScan(scanCallback)
        } catch (_: Exception) {}
        _isScanning.value = false
    }

    // ==========  BLE CONNECTION  ==========

    @SuppressLint("MissingPermission")
    fun connect(device: BluetoothDevice) {
        stopScan()
        _connectionState.value = "CONNECTING"
        Log.i(TAG, "Connecting to ${device.name ?: device.address}")
        bluetoothGatt = device.connectGatt(context, false, gattCallback, BluetoothDevice.TRANSPORT_LE)
    }

    fun bind() = startScan()

    @SuppressLint("MissingPermission")
    fun disconnect() {
        stopPolling()
        try { bluetoothGatt?.disconnect() } catch (_: Exception) {}
        try { bluetoothGatt?.close() } catch (_: Exception) {}
        bluetoothGatt = null
        toRadioChar = null
        fromRadioChar = null
        _connectionState.value = "DISCONNECTED"
        myNodeNum = 0
        _myNodeId.value = null
        _firmwareVersion.value = null
        nodeMap.clear()
        _nodes.value = emptyList()
        _radioConfig.value = null
        _deviceConfig.value = null
        _positionConfig.value = null
        _powerConfig.value = null
        _networkConfig.value = null
        _displayConfig.value = null
        _bluetoothConfig.value = null
        _channels.value = emptyList()
        _owner.value = null
        _moduleConfigs.value = emptyMap()
        Log.i(TAG, "Disconnected")
    }

    fun unbind() = disconnect()

    fun destroy() {
        disconnect()
        scope.cancel()
    }

    private var serviceDiscoveryRetries = 0
    private val maxServiceDiscoveryRetries = 3

    /**
     * Clears the BLE GATT cache via reflection.
     * This is a standard Android workaround for stale GATT service data.
     */
    @SuppressLint("MissingPermission")
    private fun refreshGattCache(gatt: BluetoothGatt): Boolean {
        return try {
            val method = gatt.javaClass.getMethod("refresh")
            method.invoke(gatt) as? Boolean ?: false
        } catch (e: Exception) {
            Log.w(TAG, "Failed to refresh GATT cache", e)
            false
        }
    }

    @SuppressLint("MissingPermission")
    private val gattCallback = object : BluetoothGattCallback() {

        override fun onConnectionStateChange(gatt: BluetoothGatt, status: Int, newState: Int) {
            when (newState) {
                BluetoothGatt.STATE_CONNECTED -> {
                    Log.i(TAG, "GATT connected, refreshing cache and requesting MTU")
                    serviceDiscoveryRetries = 0
                    refreshGattCache(gatt)
                    // Small delay to let the cache clear take effect
                    scope.launch {
                        delay(600)
                        gatt.requestMtu(MTU_SIZE)
                    }
                }
                BluetoothGatt.STATE_DISCONNECTED -> {
                    Log.w(TAG, "GATT disconnected (status=$status)")
                    _connectionState.value = "DISCONNECTED"
                }
            }
        }

        override fun onMtuChanged(gatt: BluetoothGatt, mtu: Int, status: Int) {
            Log.i(TAG, "MTU changed to $mtu")
            gatt.discoverServices()
        }

        override fun onServicesDiscovered(gatt: BluetoothGatt, status: Int) {
            if (status != BluetoothGatt.GATT_SUCCESS) {
                Log.e(TAG, "Service discovery failed: $status")
                return
            }

            val service = gatt.getService(MeshtasticBle.SERVICE_UUID)
            if (service == null) {
                Log.e(TAG, "Meshtastic BLE service not found")
                scope.launch { disconnect() }
                return
            }

            toRadioChar = service.getCharacteristic(MeshtasticBle.TORADIO_UUID)
            fromRadioChar = service.getCharacteristic(MeshtasticBle.FROMRADIO_UUID)
            val fromNumChar = service.getCharacteristic(MeshtasticBle.FROMNUM_UUID)

            if (toRadioChar == null || fromRadioChar == null) {
                Log.e(TAG, "Missing required BLE characteristics: " +
                    "toRadio=${toRadioChar != null}, fromRadio=${fromRadioChar != null}")

                if (serviceDiscoveryRetries < maxServiceDiscoveryRetries) {
                    serviceDiscoveryRetries++
                    Log.w(TAG, "Retrying service discovery (attempt $serviceDiscoveryRetries/$maxServiceDiscoveryRetries)")
                    scope.launch {
                        delay(1000L * serviceDiscoveryRetries)
                        refreshGattCache(gatt)
                        delay(500)
                        gatt.discoverServices()
                    }
                    return
                }

                Log.e(TAG, "All retries exhausted, disconnecting")
                scope.launch { disconnect() }
                return
            }

            // Enable notifications: prefer FromNum if available (legacy firmware),
            // otherwise subscribe to FromRadio notifications (firmware 2.5+)
            val notifyChar = fromNumChar ?: fromRadioChar!!
            if (fromNumChar != null) {
                Log.i(TAG, "Subscribing to FromNum notifications (legacy mode)")
            } else {
                Log.i(TAG, "FromNum not available, subscribing to FromRadio notifications (firmware 2.5+)")
            }

            gatt.setCharacteristicNotification(notifyChar, true)
            val descriptor = notifyChar.getDescriptor(MeshtasticBle.CCCD_UUID)
            if (descriptor != null) {
                descriptor.value = BluetoothGattDescriptor.ENABLE_NOTIFICATION_VALUE
                gatt.writeDescriptor(descriptor)
            } else {
                // No descriptor, proceed anyway
                onSetupComplete()
            }
        }

        override fun onDescriptorWrite(gatt: BluetoothGatt, descriptor: BluetoothGattDescriptor, status: Int) {
            Log.i(TAG, "Descriptor write status=$status")
            descriptorSemaphore.release()
            onSetupComplete()
        }

        override fun onCharacteristicRead(
            gatt: BluetoothGatt,
            characteristic: BluetoothGattCharacteristic,
            value: ByteArray,
            status: Int
        ) {
            if (status == BluetoothGatt.GATT_SUCCESS && characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                readResultQueue.add(value)
            } else {
                readResultQueue.add(null)
            }
            readSemaphore.release()
        }

        @Deprecated("Deprecated in API 33")
        override fun onCharacteristicRead(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic, status: Int) {
            if (status == BluetoothGatt.GATT_SUCCESS && characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                readResultQueue.add(characteristic.value)
            } else {
                readResultQueue.add(null)
            }
            readSemaphore.release()
        }

        override fun onCharacteristicWrite(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic, status: Int) {
            writeSemaphore.release()
        }

        override fun onCharacteristicChanged(
            gatt: BluetoothGatt,
            characteristic: BluetoothGattCharacteristic,
            value: ByteArray
        ) {
            if (characteristic.uuid == MeshtasticBle.FROMNUM_UUID) {
                // Legacy firmware: FromNum notifies that new data is available
                scope.launch { readAllFromRadio() }
            } else if (characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                // Firmware 2.5+: FromRadio notifies directly with data
                scope.launch {
                    if (value.isNotEmpty()) {
                        try {
                            val fromRadio = MeshProtos.FromRadio.parseFrom(value)
                            handleFromRadio(fromRadio)
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to parse FromRadio notification", e)
                        }
                    }
                    // There may be more queued, read remaining
                    readAllFromRadio()
                }
            }
        }

        @Deprecated("Deprecated in API 33")
        override fun onCharacteristicChanged(gatt: BluetoothGatt, characteristic: BluetoothGattCharacteristic) {
            if (characteristic.uuid == MeshtasticBle.FROMNUM_UUID) {
                scope.launch { readAllFromRadio() }
            } else if (characteristic.uuid == MeshtasticBle.FROMRADIO_UUID) {
                val value = characteristic.value
                scope.launch {
                    if (value != null && value.isNotEmpty()) {
                        try {
                            val fromRadio = MeshProtos.FromRadio.parseFrom(value)
                            handleFromRadio(fromRadio)
                        } catch (e: Exception) {
                            Log.e(TAG, "Failed to parse FromRadio notification", e)
                        }
                    }
                    readAllFromRadio()
                }
            }
        }
    }

    private var pollingJob: Job? = null

    private fun onSetupComplete() {
        _connectionState.value = "CONNECTED"
        Log.i(TAG, "BLE setup complete, requesting config")
        scope.launch {
            delay(300)
            requestConfig()
        }
        startPolling()
    }

    /**
     * Start a periodic polling loop that reads queued messages from the device.
     * This acts as a safety net in case BLE notifications are missed or coalesced.
     */
    private fun startPolling() {
        pollingJob?.cancel()
        pollingJob = scope.launch {
            while (isActive) {
                delay(POLL_INTERVAL_MS)
                if (isConnected) {
                    try {
                        readAllFromRadio()
                    } catch (e: Exception) {
                        Log.w(TAG, "Polling read failed", e)
                    }
                }
            }
        }
    }

    private fun stopPolling() {
        pollingJob?.cancel()
        pollingJob = null
    }

    // ==========  MESHTASTIC PROTOCOL  ==========

    /**
     * Request full device configuration from the connected node.
     * Public so the UI can trigger a re-read.
     */
    fun refreshConfig() {
        if (!isConnected) return
        scope.launch { requestConfig() }
    }

    private suspend fun requestConfig() {
        val configId = (System.currentTimeMillis() % Int.MAX_VALUE).toInt()
        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setWantConfigId(configId)
            .build()
        writeToRadio(toRadio)
        delay(500)
        readAllFromRadio()
    }

    @SuppressLint("MissingPermission")
    private suspend fun readAllFromRadio() {
        val gatt = bluetoothGatt ?: return
        val char = fromRadioChar ?: return

        bleMutex.withLock {
            var attempts = 0
            while (attempts < 100) {
                readSemaphore.drainPermits()
                readResultQueue.clear()

                if (!gatt.readCharacteristic(char)) break

                // Wait for callback
                if (!readSemaphore.tryAcquire(2, java.util.concurrent.TimeUnit.SECONDS)) break

                val data = readResultQueue.poll()
                if (data == null || data.isEmpty()) break

                try {
                    val fromRadio = MeshProtos.FromRadio.parseFrom(data)
                    handleFromRadio(fromRadio)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to parse FromRadio", e)
                }
                attempts++
                delay(50)
            }
        }
    }

    private fun handleFromRadio(fromRadio: MeshProtos.FromRadio) {
        when {
            fromRadio.hasMyInfo() -> {
                val info = fromRadio.myInfo
                myNodeNum = info.myNodeNum
                _myNodeId.value = MeshtasticBle.nodeNumToId(myNodeNum)
                _firmwareVersion.value = info.firmwareVersion
                Log.i(TAG, "My node: ${_myNodeId.value} (fw: ${info.firmwareVersion})")
            }

            fromRadio.hasNodeInfo() -> {
                val ni = fromRadio.nodeInfo
                val node = MeshNode(
                    nodeId = MeshtasticBle.nodeNumToId(ni.num),
                    longName = if (ni.hasUser()) ni.user.longName else "Unknown",
                    shortName = if (ni.hasUser()) ni.user.shortName else "??",
                    lastHeard = ni.lastHeard.toLong(),
                    batteryLevel = if (ni.hasDeviceMetrics()) ni.deviceMetrics.batteryLevel.toInt() else null,
                    snr = if (ni.snr != 0f) ni.snr else null
                )
                nodeMap[ni.num] = node
                _nodes.value = nodeMap.values.toList()

                // If this is our own node, capture the User as owner
                if (ni.num == myNodeNum && ni.hasUser()) {
                    _owner.value = ni.user
                }
            }

            fromRadio.hasPacket() -> handleMeshPacket(fromRadio.packet)

            fromRadio.hasConfig() -> handleConfig(fromRadio.config)

            fromRadio.hasModuleConfig() -> handleModuleConfig(fromRadio.moduleConfig)

            fromRadio.hasChannel() -> {
                val ch = fromRadio.channel
                val current = _channels.value.toMutableList()
                val idx = current.indexOfFirst { it.index == ch.index }
                if (idx >= 0) current[idx] = ch else current.add(ch)
                _channels.value = current
            }

            fromRadio.configCompleteId != 0 -> {
                Log.i(TAG, "Config complete (id=${fromRadio.configCompleteId})")
            }
        }
    }

    private fun handleConfig(config: MeshProtos.Config) {
        when {
            config.hasLora() -> {
                _radioConfig.value = config.lora
                Log.i(TAG, "LoRa config: region=${config.lora.region}, preset=${config.lora.modemPreset}")
            }
            config.hasDevice() -> {
                _deviceConfig.value = config.device
                Log.i(TAG, "Device config: role=${config.device.role}")
            }
            config.hasPosition() -> {
                _positionConfig.value = config.position
                Log.i(TAG, "Position config: gps=${config.position.gpsEnabled}, broadcast=${config.position.positionBroadcastSecs}s")
            }
            config.hasPower() -> {
                _powerConfig.value = config.power
                Log.i(TAG, "Power config: power_saving=${config.power.isPowerSaving}")
            }
            config.hasNetwork() -> {
                _networkConfig.value = config.network
                Log.i(TAG, "Network config: wifi=${config.network.wifiEnabled}")
            }
            config.hasDisplay() -> {
                _displayConfig.value = config.display
                Log.i(TAG, "Display config: screen_on=${config.display.screenOnSecs}s")
            }
            config.hasBluetooth() -> {
                _bluetoothConfig.value = config.bluetooth
                Log.i(TAG, "Bluetooth config: enabled=${config.bluetooth.enabled}, mode=${config.bluetooth.mode}")
            }
        }
    }

    private fun handleModuleConfig(moduleConfig: MeshProtos.ModuleConfig) {
        val key = when {
            moduleConfig.hasMqtt() -> "mqtt"
            moduleConfig.hasSerial() -> "serial"
            moduleConfig.hasExternalNotification() -> "external_notification"
            moduleConfig.hasStoreForward() -> "store_forward"
            moduleConfig.hasRangeTest() -> "range_test"
            moduleConfig.hasTelemetry() -> "telemetry"
            moduleConfig.hasCannedMessage() -> "canned_message"
            moduleConfig.hasAudio() -> "audio"
            moduleConfig.hasRemoteHardware() -> "remote_hardware"
            moduleConfig.hasNeighborInfo() -> "neighbor_info"
            moduleConfig.hasAmbientLighting() -> "ambient_lighting"
            moduleConfig.hasDetectionSensor() -> "detection_sensor"
            moduleConfig.hasPaxcounter() -> "paxcounter"
            else -> return
        }
        val current = _moduleConfigs.value.toMutableMap()
        current[key] = moduleConfig
        _moduleConfigs.value = current
        Log.i(TAG, "Module config received: $key")
    }

    private fun handleMeshPacket(packet: MeshProtos.MeshPacket) {
        if (!packet.hasDecoded()) return

        val data = packet.decoded
        val fromNum = packet.from
        val toNum = packet.getTo()
        val fromId = MeshtasticBle.nodeNumToId(fromNum)
        // Strict: ONLY 0xFFFFFFFF means broadcast. Other values (incl. 0 default) are DMs.
        val toId = if (toNum == MeshtasticBle.BROADCAST_ADDR) "broadcast"
                   else MeshtasticBle.nodeNumToId(toNum)
        val channel = packet.channel
        Log.d(TAG, "Packet from=$fromNum (${fromId}) to=$toNum (${toId}) ch=$channel port=${data.portnum}")

        when (data.portnum) {
            PortNum.TEXT_MESSAGE_APP -> {
                val text = data.payload.toStringUtf8()
                _incomingTextMessages.tryEmit(IncomingText(from = fromId, to = toId, text = text, channel = channel))
                Log.i(TAG, "Text from $fromId to $toId (ch=$channel): $text")
            }

            PortNum.NODEINFO_APP -> {
                try {
                    val user = MeshProtos.User.parseFrom(data.payload)
                    nodeMap[fromNum] = MeshNode(
                        nodeId = MeshtasticBle.nodeNumToId(fromNum),
                        longName = user.longName,
                        shortName = user.shortName
                    )
                    _nodes.value = nodeMap.values.toList()
                } catch (_: Exception) {}
            }

            PortNum.ADMIN_APP -> {
                // Handle admin responses (e.g. after a get_config_request)
                try {
                    val admin = MeshProtos.AdminMessage.parseFrom(data.payload)
                    handleAdminResponse(admin)
                } catch (e: Exception) {
                    Log.e(TAG, "Failed to parse AdminMessage", e)
                }
            }

            else -> {
                _incomingDataMessages.tryEmit(
                    IncomingData(from = fromId, to = toId, portNum = data.portnumValue, payload = data.payload.toByteArray(), channel = channel)
                )
            }
        }
    }

    private fun handleAdminResponse(admin: MeshProtos.AdminMessage) {
        when {
            admin.hasGetConfigResponse() -> handleConfig(admin.getConfigResponse)
            admin.hasGetModuleConfigResponse() -> handleModuleConfig(admin.getModuleConfigResponse)
            admin.hasGetChannelResponse() -> {
                val ch = admin.getChannelResponse
                val current = _channels.value.toMutableList()
                val idx = current.indexOfFirst { it.index == ch.index }
                if (idx >= 0) current[idx] = ch else current.add(ch)
                _channels.value = current
            }
            admin.hasGetOwnerResponse() -> {
                _owner.value = admin.getOwnerResponse
            }
        }
    }

    // ==========  SENDING  ==========

    @SuppressLint("MissingPermission")
    private suspend fun writeToRadio(toRadio: MeshProtos.ToRadio) {
        val gatt = bluetoothGatt ?: return
        val char = toRadioChar ?: return
        val bytes = toRadio.toByteArray()

        bleMutex.withLock {
            writeSemaphore.drainPermits()
            val initiated = if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.TIRAMISU) {
                gatt.writeCharacteristic(char, bytes, BluetoothGattCharacteristic.WRITE_TYPE_DEFAULT) == BluetoothGatt.GATT_SUCCESS
            } else {
                @Suppress("DEPRECATION")
                char.value = bytes
                @Suppress("DEPRECATION")
                char.writeType = BluetoothGattCharacteristic.WRITE_TYPE_DEFAULT
                @Suppress("DEPRECATION")
                gatt.writeCharacteristic(char)
            }
            if (initiated) {
                if (!writeSemaphore.tryAcquire(2, java.util.concurrent.TimeUnit.SECONDS)) {
                    Log.w(TAG, "Write timeout waiting for callback (${bytes.size} bytes)")
                } else {
                    Log.d(TAG, "ToRadio write success (${bytes.size} bytes)")
                }
            } else {
                Log.e(TAG, "Failed to initiate BLE write ToRadio (${bytes.size} bytes)")
            }
        }
    }

    fun sendText(text: String, destination: String? = null, channel: Int = 0): Boolean {
        if (!isConnected) return false

        val destNum = if (destination != null) {
            MeshtasticBle.nodeIdToNum(destination) ?: run {
                Log.e(TAG, "Invalid destination node ID: $destination")
                return false
            }
        } else {
            MeshtasticBle.BROADCAST_ADDR
        }

        val data = MeshProtos.Data.newBuilder()
            .setPortnum(PortNum.TEXT_MESSAGE_APP)
            .setPayload(com.google.protobuf.ByteString.copyFromUtf8(text))
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(destNum)
            .setChannel(channel)
            .setDecoded(data)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        Log.i(TAG, "Sending text to ${destination ?: "broadcast"} (dest=$destNum): $text")
        return true
    }

    fun sendData(data: ByteArray, portNum: Int, destination: String? = null, channel: Int = 0): Boolean {
        if (!isConnected) return false

        val destNum = if (destination != null) {
            MeshtasticBle.nodeIdToNum(destination) ?: run {
                Log.e(TAG, "Invalid destination node ID: $destination")
                return false
            }
        } else {
            MeshtasticBle.BROADCAST_ADDR
        }

        val meshData = MeshProtos.Data.newBuilder()
            .setPortnumValue(portNum)
            .setPayload(com.google.protobuf.ByteString.copyFrom(data))
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(destNum)
            .setChannel(channel)
            .setDecoded(meshData)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        Log.i(TAG, "Sending data (port=$portNum, ${data.size} bytes) to ${destination ?: "broadcast"}")
        return true
    }

    // ==========  ADMIN CONFIG WRITES (local node only)  ==========

    private fun sendAdminMessage(admin: MeshProtos.AdminMessage): Boolean {
        if (!isConnected || myNodeNum == 0) return false

        val data = MeshProtos.Data.newBuilder()
            .setPortnum(PortNum.ADMIN_APP)
            .setPayload(admin.toByteString())
            .setWantResponse(true)
            .build()

        val packet = MeshProtos.MeshPacket.newBuilder()
            .setTo(myNodeNum)
            .setDecoded(data)
            .setWantAck(true)
            .build()

        val toRadio = MeshProtos.ToRadio.newBuilder()
            .setPacket(packet)
            .build()

        scope.launch { writeToRadio(toRadio) }
        return true
    }

    /**
     * Write a Config section (LoRa, Device, Position, Power, Network, Display, Bluetooth)
     * to the local connected device.
     */
    fun writeConfig(config: MeshProtos.Config): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetConfig(config)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write a ModuleConfig section to the local connected device.
     */
    fun writeModuleConfig(moduleConfig: MeshProtos.ModuleConfig): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetModuleConfig(moduleConfig)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write a Channel configuration to the local connected device.
     */
    fun writeChannel(channel: MeshProtos.Channel): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetChannel(channel)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Write the User/Owner info to the local connected device.
     */
    fun writeOwner(user: MeshProtos.User): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setSetOwner(user)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Reboot the device after the specified number of seconds.
     */
    fun rebootDevice(seconds: Int = 5): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setRebootSeconds(seconds)
            .build()
        return sendAdminMessage(admin)
    }

    /**
     * Factory reset the device.
     */
    fun factoryReset(): Boolean {
        val admin = MeshProtos.AdminMessage.newBuilder()
            .setFactoryReset(true)
            .build()
        return sendAdminMessage(admin)
    }

    // ==========  LEGACY CONFIG ACCESSORS  ==========

    fun getRadioConfig(): ByteArray? = _radioConfig.value?.toByteArray()

    fun setRadioConfig(config: ByteArray): Boolean {
        Log.i(TAG, "setRadioConfig: ${config.size} bytes")
        return isConnected
    }

    fun getChannels(): ByteArray? = null

    fun setChannels(channels: ByteArray): Boolean {
        Log.i(TAG, "setChannels: ${channels.size} bytes")
        return isConnected
    }
}

package re.chasam.voicetastic.ui.chat

import android.content.Context
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import re.chasam.voicetastic.model.ChatItem
import re.chasam.voicetastic.model.MeshNode
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.service.MeshServiceManager
import re.chasam.voicetastic.service.Portnums
import re.chasam.voicetastic.voice.VoiceAssembler
import re.chasam.voicetastic.voice.VoiceChunker
import re.chasam.voicetastic.voice.VoicePlayer
import re.chasam.voicetastic.voice.VoiceRecorder
import java.io.File

/**
 * ViewModel for the unified chat screen (text + voice messages).
 */
class MessagingViewModel(
    private val meshService: MeshServiceManager,
    private val context: Context,
    private val voiceConfig: MutableStateFlow<VoiceConfig> = MutableStateFlow(VoiceConfig())
) : ViewModel() {

    // Master list of ALL chat items (unfiltered)
    private val _allChatItems = MutableStateFlow<List<ChatItem>>(emptyList())

    private val _selectedNode = MutableStateFlow<MeshNode?>(null)
    val selectedNode: StateFlow<MeshNode?> = _selectedNode.asStateFlow()

    private val _selectedChannel = MutableStateFlow(0)
    val selectedChannel: StateFlow<Int> = _selectedChannel.asStateFlow()

    /**
     * Filtered chat items for the currently-selected conversation.
     *
     * Conversation identity uses each message's pre-computed `contactKey`:
     *   - selectedNode == null  → conversation key = "broadcast"
     *   - selectedNode != null  → conversation key = selectedNode.nodeId
     *
     * Mirrors the meshtastic-android Contact model: each message belongs to
     * exactly one conversation, decided at ingestion time. No perspective-
     * dependent or fallback logic at filter time.
     */
    val chatItems: StateFlow<List<ChatItem>> = combine(
        _allChatItems,
        _selectedNode,
        _selectedChannel
    ) { items, node, channel ->
        val conversationKey = node?.nodeId ?: "broadcast"
        items.filter { it.channel == channel && it.contactKey == conversationKey }
    }.stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())

    val nodes: StateFlow<List<MeshNode>> = meshService.nodes
    val connectionState: StateFlow<String> = meshService.connectionState

    /**
     * Available channels as (index, name) pairs, derived from the device's channel config.
     * Always includes at least channel 0 ("Primary").
     */
    val availableChannels: StateFlow<List<Pair<Int, String>>> = meshService.channels
        .map { channelList ->
            if (channelList.isEmpty()) {
                listOf(0 to "Primary")
            } else {
                channelList.map { ch ->
                    val name = if (ch.hasSettings() && ch.settings.name.isNotBlank()) {
                        ch.settings.name
                    } else if (ch.index == 0) {
                        "Primary"
                    } else {
                        "Channel ${ch.index}"
                    }
                    ch.index to name
                }
            }
        }
        .stateIn(viewModelScope, SharingStarted.Eagerly, listOf(0 to "Primary"))

    // Voice state
    private val recorder = VoiceRecorder(context)
    private val player = VoicePlayer()
    private val assembler = VoiceAssembler(
        chunkTimeoutSeconds = voiceConfig.value.chunkTimeoutSeconds,
        partialPlayOnTimeout = voiceConfig.value.partialPlayOnTimeout,
        scope = viewModelScope
    )

    private val _isRecording = MutableStateFlow(false)
    val isRecording: StateFlow<Boolean> = _isRecording.asStateFlow()

    private val _isPlaying = MutableStateFlow(false)
    val isPlaying: StateFlow<Boolean> = _isPlaying.asStateFlow()

    private val _playingItemId = MutableStateFlow<Int?>(null)
    val playingItemId: StateFlow<Int?> = _playingItemId.asStateFlow()

    private val _sendingProgress = MutableStateFlow<Float?>(null)
    val sendingProgress: StateFlow<Float?> = _sendingProgress.asStateFlow()

    val config: StateFlow<VoiceConfig> = voiceConfig.asStateFlow()

    private var itemIdCounter = 0
    private var voiceMessageIdSeq = (System.currentTimeMillis() % 65536).toInt()
    private var currentRecordingFile: File? = null

    init {
        observeIncomingTextMessages()
        observeIncomingVoiceData()
        observeCompletedVoiceMessages()

        player.onCompletion = {
            _isPlaying.value = false
            _playingItemId.value = null
        }
    }

    private fun observeIncomingTextMessages() {
        viewModelScope.launch {
            meshService.incomingTextMessages.collect { incoming ->
                val item = ChatItem.Text(
                    id = ++itemIdCounter,
                    text = incoming.text,
                    from = incoming.from,
                    to = incoming.to,
                    timestamp = incoming.timestamp,
                    isOutgoing = false,
                    channel = incoming.channel,
                    contactKey = computeContactKey(incoming.from, incoming.to, isOutgoing = false)
                )
                _allChatItems.value = _allChatItems.value + item
            }
        }
    }

    private fun observeIncomingVoiceData() {
        viewModelScope.launch {
            meshService.incomingDataMessages.collect { data ->
                if (data.portNum == Portnums.PRIVATE_APP) {
                    assembler.onChunkReceived(
                        from = data.from,
                        chunkData = data.payload,
                        destinationId = data.to,
                        channel = data.channel
                    )
                }
            }
        }
    }

    private fun observeCompletedVoiceMessages() {
        viewModelScope.launch {
            assembler.completedMessages.collect { msg ->
                val item = ChatItem.Voice(
                    id = ++itemIdCounter,
                    from = msg.from,
                    to = msg.to,
                    audioData = msg.audioData,
                    timestamp = msg.timestamp,
                    isOutgoing = false,
                    isComplete = msg.isComplete,
                    totalChunks = msg.totalChunks,
                    receivedChunks = msg.receivedChunks,
                    bitrateIndex = msg.bitrateIndex,
                    channel = msg.channel,
                    contactKey = computeContactKey(msg.from, msg.to, isOutgoing = false)
                )
                _allChatItems.value = _allChatItems.value + item
            }
        }
    }

    // ========== TEXT MESSAGING ==========

    /**
     * Send a text message to the selected node, or broadcast if no node selected.
     */
    fun sendMessage(text: String) {
        if (text.isBlank()) return

        val destination = _selectedNode.value?.nodeId
        val channel = _selectedChannel.value
        val success = meshService.sendText(text, destination, channel)

        if (success) {
            val myId = meshService.myNodeId.value ?: "me"
            val toField = destination ?: "broadcast"
            val item = ChatItem.Text(
                id = ++itemIdCounter,
                text = text,
                from = myId,
                to = toField,
                timestamp = System.currentTimeMillis(),
                isOutgoing = true,
                channel = channel,
                contactKey = computeContactKey(myId, toField, isOutgoing = true)
            )
            _allChatItems.value = _allChatItems.value + item
        }
    }

    // ========== VOICE MESSAGING ==========

    /**
     * Start recording a voice message.
     */
    fun startRecording() {
        if (_isRecording.value) return

        currentRecordingFile = recorder.startRecording(voiceConfig.value)
        if (currentRecordingFile != null) {
            _isRecording.value = true
        }
    }

    /**
     * Stop recording and send the voice message.
     */
    fun stopRecordingAndSend() {
        if (!_isRecording.value) return

        val file = recorder.stopRecording()
        _isRecording.value = false

        if (file != null && file.exists() && file.length() > 0) {
            viewModelScope.launch {
                sendVoiceFile(file)
            }
        }
    }

    /**
     * Cancel current recording without sending.
     */
    fun cancelRecording() {
        recorder.stopRecording()
        _isRecording.value = false
        currentRecordingFile?.delete()
        currentRecordingFile = null
    }

    private suspend fun sendVoiceFile(file: File) {
        val audioData = file.readBytes()
        val msgId = voiceMessageIdSeq++ and 0xFFFF

        val chunks = VoiceChunker.chunkAudio(
            audioData = audioData,
            messageId = msgId,
            bitrate = voiceConfig.value.bitrate
        )

        val destination = _selectedNode.value?.nodeId
        val channel = _selectedChannel.value

        _sendingProgress.value = 0f
        chunks.forEachIndexed { index, chunk ->
            meshService.sendData(
                data = chunk,
                portNum = Portnums.PRIVATE_APP,
                destination = destination,
                channel = channel
            )
            _sendingProgress.value = (index + 1).toFloat() / chunks.size
            delay(500)
        }
        _sendingProgress.value = null

        // Add to chat as outgoing voice item
        val myId = meshService.myNodeId.value ?: "me"
        val toField = destination ?: "broadcast"
        val item = ChatItem.Voice(
            id = ++itemIdCounter,
            from = myId,
            to = toField,
            audioData = audioData,
            isOutgoing = true,
            isComplete = true,
            totalChunks = chunks.size,
            receivedChunks = chunks.size,
            bitrateIndex = voiceConfig.value.bitrate.ordinal,
            channel = channel,
            contactKey = computeContactKey(myId, toField, isOutgoing = true)
        )
        _allChatItems.value = _allChatItems.value + item

        file.delete()
    }

    /**
     * Play a voice message.
     */
    fun playVoiceMessage(item: ChatItem.Voice) {
        if (_isPlaying.value && _playingItemId.value == item.id) {
            player.stop()
            _isPlaying.value = false
            _playingItemId.value = null
            return
        }

        _isPlaying.value = true
        _playingItemId.value = item.id
        player.play(item.audioData, context.cacheDir)
    }

    /**
     * Stop playback.
     */
    fun stopPlayback() {
        player.stop()
        _isPlaying.value = false
        _playingItemId.value = null
    }

    // ========== COMMON ==========

    /**
     * Select a node to send messages to. Null = broadcast mode.
     */
    fun selectNode(node: MeshNode?) {
        _selectedNode.value = node
    }

    /**
     * Select the channel index for sending and filtering messages.
     */
    fun selectChannel(channel: Int) {
        _selectedChannel.value = channel
    }

    /**
     * Clear the message history.
     */
    fun clearMessages() {
        _allChatItems.value = emptyList()
    }

    override fun onCleared() {
        super.onCleared()
        player.release()
        assembler.destroy()
    }
}

package re.chasam.voicetastic.ui.chat

import android.content.Context
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import re.chasam.voicetastic.model.ChatItem
import re.chasam.voicetastic.model.MeshNode
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.service.MeshServiceManager
import re.chasam.voicetastic.service.Portnums
import re.chasam.voicetastic.voice.VoiceAssembler
import re.chasam.voicetastic.voice.VoiceChunker
import re.chasam.voicetastic.voice.VoicePlayer
import re.chasam.voicetastic.voice.VoiceRecorder
import java.io.File

/**
 * ViewModel for the unified chat screen (text + voice messages).
 */
class MessagingViewModel(
    private val meshService: MeshServiceManager,
    private val context: Context,
    private val voiceConfig: MutableStateFlow<VoiceConfig> = MutableStateFlow(VoiceConfig())
) : ViewModel() {

    // Master list of ALL chat items (unfiltered)
    private val _allChatItems = MutableStateFlow<List<ChatItem>>(emptyList())

    private val _selectedNode = MutableStateFlow<MeshNode?>(null)
    val selectedNode: StateFlow<MeshNode?> = _selectedNode.asStateFlow()

    private val _selectedChannel = MutableStateFlow(0)
    val selectedChannel: StateFlow<Int> = _selectedChannel.asStateFlow()

    /**
     * Filtered chat items for the currently-selected conversation.
     *
     * Conversation identity uses each message's pre-computed `contactKey`:
     *   - selectedNode == null  → conversation key = "broadcast"
     *   - selectedNode != null  → conversation key = selectedNode.nodeId
     *
     * Mirrors the meshtastic-android Contact model: each message belongs to
     * exactly one conversation, decided at ingestion time. No perspective-
     * dependent or fallback logic at filter time.
     */
    val chatItems: StateFlow<List<ChatItem>> = combine(
        _allChatItems,
        _selectedNode,
        _selectedChannel
    ) { items, node, channel ->
        val conversationKey = node?.nodeId ?: "broadcast"
        items.filter { it.channel == channel && it.contactKey == conversationKey }
    }.stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())

    val nodes: StateFlow<List<MeshNode>> = meshService.nodes
    val connectionState: StateFlow<String> = meshService.connectionState

    /**
     * Available channels as (index, name) pairs, derived from the device's channel config.
     * Always includes at least channel 0 ("Primary").
     */
    val availableChannels: StateFlow<List<Pair<Int, String>>> = meshService.channels
        .map { channelList ->
            if (channelList.isEmpty()) {
                listOf(0 to "Primary")
            } else {
                channelList.map { ch ->
                    val name = if (ch.hasSettings() && ch.settings.name.isNotBlank()) {
                        ch.settings.name
                    } else if (ch.index == 0) {
                        "Primary"
                    } else {
                        "Channel ${ch.index}"
                    }
                    ch.index to name
                }
            }
        }
        .stateIn(viewModelScope, SharingStarted.Eagerly, listOf(0 to "Primary"))

    // Voice state
    private val recorder = VoiceRecorder(context)
    private val player = VoicePlayer()
    private val assembler = VoiceAssembler(
        chunkTimeoutSeconds = voiceConfig.value.chunkTimeoutSeconds,
        partialPlayOnTimeout = voiceConfig.value.partialPlayOnTimeout,
        scope = viewModelScope
    )

    private val _isRecording = MutableStateFlow(false)
    val isRecording: StateFlow<Boolean> = _isRecording.asStateFlow()

    private val _isPlaying = MutableStateFlow(false)
    val isPlaying: StateFlow<Boolean> = _isPlaying.asStateFlow()

    private val _playingItemId = MutableStateFlow<Int?>(null)
    val playingItemId: StateFlow<Int?> = _playingItemId.asStateFlow()

    private val _sendingProgress = MutableStateFlow<Float?>(null)
    val sendingProgress: StateFlow<Float?> = _sendingProgress.asStateFlow()

    val config: StateFlow<VoiceConfig> = voiceConfig.asStateFlow()

    private var itemIdCounter = 0
    private var voiceMessageIdSeq = (System.currentTimeMillis() % 65536).toInt()
    private var currentRecordingFile: File? = null

    init {
        observeIncomingTextMessages()
        observeIncomingVoiceData()
        observeCompletedVoiceMessages()

        player.onCompletion = {
            _isPlaying.value = false
            _playingItemId.value = null
        }
    }

    private fun observeIncomingTextMessages() {
        viewModelScope.launch {
            meshService.incomingTextMessages.collect { incoming ->
                val item = ChatItem.Text(
                    id = ++itemIdCounter,
                    text = incoming.text,
                    from = incoming.from,
                    to = incoming.to,
                    timestamp = incoming.timestamp,
                    isOutgoing = false,
                    channel = incoming.channel,
                    contactKey = computeContactKey(incoming.from, incoming.to, isOutgoing = false)
                )
                _allChatItems.value = _allChatItems.value + item
            }
        }
    }

    private fun observeIncomingVoiceData() {
        viewModelScope.launch {
            meshService.incomingDataMessages.collect { data ->
                if (data.portNum == Portnums.PRIVATE_APP) {
                    assembler.onChunkReceived(
                        from = data.from,
                        chunkData = data.payload,
                        destinationId = data.to,
                        channel = data.channel
                    )
                }
            }
        }
    }

    private fun observeCompletedVoiceMessages() {
        viewModelScope.launch {
            assembler.completedMessages.collect { msg ->
                val item = ChatItem.Voice(
                    id = ++itemIdCounter,
                    from = msg.from,
                    to = msg.to,
                    audioData = msg.audioData,
                    timestamp = msg.timestamp,
                    isOutgoing = false,
                    isComplete = msg.isComplete,
                    totalChunks = msg.totalChunks,
                    receivedChunks = msg.receivedChunks,
                    bitrateIndex = msg.bitrateIndex,
                    channel = msg.channel,
                    contactKey = computeContactKey(msg.from, msg.to, isOutgoing = false)
                )
                _allChatItems.value = _allChatItems.value + item
            }
        }
    }

    // ========== TEXT MESSAGING ==========

    /**
     * Send a text message to the selected node, or broadcast if no node selected.
     */
    fun sendMessage(text: String) {
        if (text.isBlank()) return

        val destination = _selectedNode.value?.nodeId
        val channel = _selectedChannel.value
        val success = meshService.sendText(text, destination, channel)

        if (success) {
            val myId = meshService.myNodeId.value ?: "me"
            val toField = destination ?: "broadcast"
            val item = ChatItem.Text(
                id = ++itemIdCounter,
                text = text,
                from = myId,
                to = toField,
                timestamp = System.currentTimeMillis(),
                isOutgoing = true,
                channel = channel,
                contactKey = computeContactKey(myId, toField, isOutgoing = true)
            )
            _allChatItems.value = _allChatItems.value + item
        }
    }

    // ========== VOICE MESSAGING ==========

    /**
     * Start recording a voice message.
     */
    fun startRecording() {
        if (_isRecording.value) return

        currentRecordingFile = recorder.startRecording(voiceConfig.value)
        if (currentRecordingFile != null) {
            _isRecording.value = true
        }
    }

    /**
     * Stop recording and send the voice message.
     */
    fun stopRecordingAndSend() {
        if (!_isRecording.value) return

        val file = recorder.stopRecording()
        _isRecording.value = false

        if (file != null && file.exists() && file.length() > 0) {
            viewModelScope.launch {
                sendVoiceFile(file)
            }
        }
    }

    /**
     * Cancel current recording without sending.
     */
    fun cancelRecording() {
        recorder.stopRecording()
        _isRecording.value = false
        currentRecordingFile?.delete()
        currentRecordingFile = null
    }

    private suspend fun sendVoiceFile(file: File) {
        val audioData = file.readBytes()
        val msgId = voiceMessageIdSeq++ and 0xFFFF

        val chunks = VoiceChunker.chunkAudio(
            audioData = audioData,
            messageId = msgId,
            bitrate = voiceConfig.value.bitrate
        )

        val destination = _selectedNode.value?.nodeId
        val channel = _selectedChannel.value

        _sendingProgress.value = 0f
        chunks.forEachIndexed { index, chunk ->
            meshService.sendData(
                data = chunk,
                portNum = Portnums.PRIVATE_APP,
                destination = destination,
                channel = channel
            )
            _sendingProgress.value = (index + 1).toFloat() / chunks.size
            delay(500)
        }
        _sendingProgress.value = null

        // Add to chat as outgoing voice item
        val myId = meshService.myNodeId.value ?: "me"
        val toField = destination ?: "broadcast"
        val item = ChatItem.Voice(
            id = ++itemIdCounter,
            from = myId,
            to = toField,
            audioData = audioData,
            isOutgoing = true,
            isComplete = true,
            totalChunks = chunks.size,
            receivedChunks = chunks.size,
            bitrateIndex = voiceConfig.value.bitrate.ordinal,
            channel = channel,
            contactKey = computeContactKey(myId, toField, isOutgoing = true)
        )
        _allChatItems.value = _allChatItems.value + item

        file.delete()
    }

    /**
     * Play a voice message.
     */
    fun playVoiceMessage(item: ChatItem.Voice) {
        if (_isPlaying.value && _playingItemId.value == item.id) {
            player.stop()
            _isPlaying.value = false
            _playingItemId.value = null
            return
        }

        _isPlaying.value = true
        _playingItemId.value = item.id
        player.play(item.audioData, context.cacheDir)
    }

    /**
     * Stop playback.
     */
    fun stopPlayback() {
        player.stop()
        _isPlaying.value = false
        _playingItemId.value = null
    }

    // ========== COMMON ==========

    /**
     * Select a node to send messages to. Null = broadcast mode.
     */
    fun selectNode(node: MeshNode?) {
        _selectedNode.value = node
    }

    /**
     * Select the channel index for sending and filtering messages.
     */
    fun selectChannel(channel: Int) {
        _selectedChannel.value = channel
    }

    /**
     * Clear the message history.
     */
    fun clearMessages() {
        _allChatItems.value = emptyList()
    }

    /**
     * Compute the conversation key for a message from this node's perspective.
     *
     *  - Outgoing broadcast (to == "broadcast")            → "broadcast"
     *  - Outgoing DM (to == some node id)                  → that node id
     *  - Incoming broadcast (to == "broadcast")            → "broadcast"
     *  - Incoming DM addressed to me (to == myId)          → the sender
     *  - Incoming overheard DM (to == some other node id)  → the sender
     *    (we never had this conversation, but group it with the sender so
     *     it doesn't pollute the broadcast/channel view)
     */
    private fun computeContactKey(
        from: String,
        to: String,
        isOutgoing: Boolean
    ): String {
        val myId = meshService.myNodeId.value ?: ""
        return when {
            to == "broadcast" -> "broadcast"
            isOutgoing -> to
            to == myId -> from
            else -> from
        }
    }

    override fun onCleared() {
        super.onCleared()
        player.release()
        assembler.destroy()
    }
}

package re.chasam.voicetastic.voice

import android.util.Log
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.asSharedFlow
import re.chasam.voicetastic.model.VoiceMessage
import java.io.ByteArrayOutputStream

/**
 * Reassembles incoming voice chunks into complete voice messages.
 *
 * Handles out-of-order delivery, missing chunks (with timeout + partial play),
 * and concurrent messages from different senders.
 */
class VoiceAssembler(
    private val chunkTimeoutSeconds: Int = 30,
    private val partialPlayOnTimeout: Boolean = true,
    private val scope: CoroutineScope = CoroutineScope(Dispatchers.Default + SupervisorJob())
) {

    companion object {
        private const val TAG = "VoiceAssembler"
        /** AMR-NB file header: "#!AMR\n" */
        val AMR_HEADER = byteArrayOf(0x23, 0x21, 0x41, 0x4D, 0x52, 0x0A)
    }

    /**
     * Key for tracking in-progress voice messages: (senderNodeId, messageId).
     */
    private data class AssemblyKey(val from: String, val messageId: Int)

    /**
     * Internal state for an in-progress voice message assembly.
     */
    private class AssemblyState(
        val from: String,
        val messageId: Int,
        val totalChunks: Int,
        val bitrateIndex: Int,
        val destinationId: String = "",
        val channel: Int = 0,
        val startTime: Long = System.currentTimeMillis()
    ) {
        val chunks: MutableMap<Int, ByteArray> = mutableMapOf()
        var timeoutJob: Job? = null

        val isComplete: Boolean
            get() = chunks.size == totalChunks

        val receivedCount: Int
            get() = chunks.size
    }

    private val assemblies = mutableMapOf<AssemblyKey, AssemblyState>()

    private val _completedMessages = MutableSharedFlow<VoiceMessage>(extraBufferCapacity = 16)
    val completedMessages: SharedFlow<VoiceMessage> = _completedMessages.asSharedFlow()

    /**
     * Feed an incoming voice data chunk into the assembler.
     *
     * @param from sender node ID
     * @param chunkData raw chunk bytes (header + payload)
     * @param destinationId the destination node ID (or broadcast)
     * @param channel the Meshtastic channel index
     */
    fun onChunkReceived(from: String, chunkData: ByteArray, destinationId: String = "", channel: Int = 0) {
        val header = VoiceChunker.parseHeader(chunkData) ?: run {
            Log.w(TAG, "Invalid chunk header from $from")
            return
        }

        val payload = VoiceChunker.extractPayload(chunkData)
        val key = AssemblyKey(from, header.messageId)

        synchronized(assemblies) {
            val state = assemblies.getOrPut(key) {
                val newState = AssemblyState(
                    from = from,
                    messageId = header.messageId,
                    totalChunks = header.totalChunks,
                    bitrateIndex = header.bitrateIndex,
                    destinationId = destinationId,
                    channel = channel
                )
                // Start timeout timer
                newState.timeoutJob = scope.launch {
                    delay(chunkTimeoutSeconds * 1000L)
                    onTimeout(key)
                }
                newState
            }

            // Store the chunk (ignore duplicates)
            if (!state.chunks.containsKey(header.chunkIndex)) {
                state.chunks[header.chunkIndex] = payload
                Log.d(TAG, "Chunk ${header.chunkIndex + 1}/${header.totalChunks} " +
                        "for msg ${header.messageId} from $from")
            }

            // Check if complete
            if (state.isComplete) {
                state.timeoutJob?.cancel()
                finalizeMessage(key, state, isPartial = false)
            }
        }
    }

    /**
     * Called when the timeout elapses for an incomplete message.
     */
    private fun onTimeout(key: AssemblyKey) {
        synchronized(assemblies) {
            val state = assemblies[key] ?: return
            Log.w(TAG, "Timeout for msg ${key.messageId} from ${key.from}: " +
                    "${state.receivedCount}/${state.totalChunks} chunks received")

            if (partialPlayOnTimeout && state.receivedCount > 0) {
                finalizeMessage(key, state, isPartial = true)
            } else {
                assemblies.remove(key)
                Log.w(TAG, "Discarding incomplete message ${key.messageId}")
            }
        }
    }

    /**
     * Assemble audio data from received chunks and emit a completed VoiceMessage.
     */
    private fun finalizeMessage(key: AssemblyKey, state: AssemblyState, isPartial: Boolean) {
        val audioData = assembleAudio(state)
        val message = VoiceMessage(
            messageId = state.messageId,
            from = state.from,
            to = state.destinationId,
            audioData = audioData,
            timestamp = state.startTime,
            isComplete = !isPartial,
            totalChunks = state.totalChunks,
            receivedChunks = state.receivedCount,
            bitrateIndex = state.bitrateIndex,
            channel = state.channel
        )
        assemblies.remove(key)
        _completedMessages.tryEmit(message)

        if (isPartial) {
            Log.i(TAG, "Emitting partial voice message ${state.messageId}: " +
                    "${state.receivedCount}/${state.totalChunks} chunks")
        } else {
            Log.i(TAG, "Emitting complete voice message ${state.messageId}")
        }
    }

    /**
     * Concatenate chunks in order, filling silence for missing ones.
     * Returns a valid AMR-NB byte stream (with file header).
     */
    private fun assembleAudio(state: AssemblyState): ByteArray {
        val output = ByteArrayOutputStream()

        // Write AMR-NB file header
        output.write(AMR_HEADER)

        // Write chunks in order
        for (i in 0 until state.totalChunks) {
            val chunkPayload = state.chunks[i]
            if (chunkPayload != null) {
                output.write(chunkPayload)
            } else {
                // Fill with silence frame for missing chunk
                // AMR-NB silence frame (NO_DATA mode, ~1 byte)
                output.write(createSilenceFrame())
            }
        }

        return output.toByteArray()
    }

    /**
     * Create a minimal AMR-NB silence frame.
     * Frame type 15 (NO_DATA) = single byte 0x7C
     */
    private fun createSilenceFrame(): ByteArray {
        // AMR-NB NO_DATA frame: frame type 15, padded
        return byteArrayOf(0x7C)
    }

    /**
     * Get the number of messages currently being assembled.
     */
    fun pendingCount(): Int = synchronized(assemblies) { assemblies.size }

    /**
     * Clear all pending assemblies and cancel timeouts.
     */
    fun clear() {
        synchronized(assemblies) {
            assemblies.values.forEach { it.timeoutJob?.cancel() }
            assemblies.clear()
        }
    }

    /**
     * Shut down the assembler and release resources.
     */
    fun destroy() {
        clear()
        scope.cancel()
    }
}

package re.chasam.voicetastic.voice

import android.util.Log
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import re.chasam.voicetastic.model.AmrNbBitrate
import re.chasam.voicetastic.model.VoiceMessage
import java.io.ByteArrayOutputStream

/**
 * Reassembles incoming voice chunks into complete voice messages.
 *
 * Handles out-of-order delivery, missing chunks (with timeout + partial play),
 * and concurrent messages from different senders.
 *
 * Uses a coroutine [Mutex] instead of `synchronized` for suspension-friendly locking.
 * Maintains a recently-completed blacklist to reject stale duplicate chunks
 * that arrive after a message has already been finalized.
 */
class VoiceAssembler(
    private val chunkTimeoutSeconds: Int = 30,
    private val partialPlayOnTimeout: Boolean = true,
    private val scope: CoroutineScope = CoroutineScope(Dispatchers.Default + SupervisorJob())
) {

    companion object {
        private const val TAG = "VoiceAssembler"
        /** AMR-NB file header: "#!AMR\n" */
        val AMR_HEADER = byteArrayOf(0x23, 0x21, 0x41, 0x4D, 0x52, 0x0A)
        /** AMR-NB NO_DATA silence frame (frame type 15) */
        private val SILENCE_FRAME = byteArrayOf(0x7C)
        /** How long to remember completed messages to reject late duplicates */
        private const val BLACKLIST_EXPIRY_MS = 60_000L
        /** Max blacklist size to prevent unbounded growth */
        private const val MAX_BLACKLIST_SIZE = 100
    }

    /**
     * Key for tracking in-progress voice messages: (senderNodeId, messageId).
     */
    private data class AssemblyKey(val from: String, val messageId: Int)

    /**
     * Internal state for an in-progress voice message assembly.
     */
    private class AssemblyState(
        val from: String,
        val messageId: Int,
        val totalChunks: Int,
        val bitrateIndex: Int,
        val destinationId: String = "",
        val channel: Int = 0,
        val startTime: Long = System.currentTimeMillis()
    ) {
        val chunks: MutableMap<Int, ByteArray> = mutableMapOf()
        var timeoutJob: Job? = null

        val isComplete: Boolean
            get() = chunks.size == totalChunks

        val receivedCount: Int
            get() = chunks.size
    }

    private val mutex = Mutex()
    private val assemblies = mutableMapOf<AssemblyKey, AssemblyState>()

    /** Recently-completed message keys with their completion timestamp */
    private val recentlyCompleted = LinkedHashMap<AssemblyKey, Long>()

    private val _completedMessages = MutableSharedFlow<VoiceMessage>(extraBufferCapacity = 16)
    val completedMessages: SharedFlow<VoiceMessage> = _completedMessages.asSharedFlow()

    /**
     * Feed an incoming voice data chunk into the assembler.
     *
     * @param from sender node ID
     * @param chunkData raw chunk bytes (header + payload)
     * @param destinationId the destination node ID (or broadcast)
     * @param channel the Meshtastic channel index
     */
    fun onChunkReceived(from: String, chunkData: ByteArray, destinationId: String = "", channel: Int = 0) {
        val header = VoiceChunker.parseHeader(chunkData) ?: run {
            Log.w(TAG, "Invalid chunk header from $from")
            return
        }

        val payload = VoiceChunker.extractPayload(chunkData)
        val key = AssemblyKey(from, header.messageId)

        scope.launch {
            mutex.withLock {
                // Reject chunks for recently-completed messages (late duplicates)
                if (recentlyCompleted.containsKey(key)) {
                    Log.d(TAG, "Ignoring late chunk for completed msg ${key.messageId} from ${key.from}")
                    return@withLock
                }

                val state = assemblies.getOrPut(key) {
                    val newState = AssemblyState(
                        from = from,
                        messageId = header.messageId,
                        totalChunks = header.totalChunks,
                        bitrateIndex = header.bitrateIndex,
                        destinationId = destinationId,
                        channel = channel
                    )
                    // Start timeout timer
                    newState.timeoutJob = scope.launch {
                        delay(chunkTimeoutSeconds * 1000L)
                        onTimeout(key)
                    }
                    newState
                }

                // Store the chunk (ignore duplicates)
                if (!state.chunks.containsKey(header.chunkIndex)) {
                    state.chunks[header.chunkIndex] = payload
                    Log.d(TAG, "Chunk ${header.chunkIndex + 1}/${header.totalChunks} " +
                            "for msg ${header.messageId} from $from")
                }

                // Check if complete
                if (state.isComplete) {
                    state.timeoutJob?.cancel()
                    finalizeMessage(key, state, isPartial = false)
                }
            }
        }
    }

    /**
     * Called when the timeout elapses for an incomplete message.
     */
    private suspend fun onTimeout(key: AssemblyKey) {
        mutex.withLock {
            val state = assemblies[key] ?: return
            Log.w(TAG, "Timeout for msg ${key.messageId} from ${key.from}: " +
                    "${state.receivedCount}/${state.totalChunks} chunks received")

            if (partialPlayOnTimeout && state.receivedCount > 0) {
                finalizeMessage(key, state, isPartial = true)
            } else {
                assemblies.remove(key)
                Log.w(TAG, "Discarding incomplete message ${key.messageId}")
            }
        }
    }

    /**
     * Assemble audio data from received chunks and emit a completed VoiceMessage.
     * Must be called while holding [mutex].
     */
    private fun finalizeMessage(key: AssemblyKey, state: AssemblyState, isPartial: Boolean) {
        val audioData = assembleAudio(state)
        val message = VoiceMessage(
            messageId = state.messageId,
            from = state.from,
            to = state.destinationId,
            audioData = audioData,
            timestamp = state.startTime,
            isComplete = !isPartial,
            totalChunks = state.totalChunks,
            receivedChunks = state.receivedCount,
            bitrateIndex = state.bitrateIndex,
            channel = state.channel
        )
        assemblies.remove(key)

        // Add to blacklist to reject late duplicates
        addToBlacklist(key)

        _completedMessages.tryEmit(message)

        if (isPartial) {
            Log.i(TAG, "Emitting partial voice message ${state.messageId}: " +
                    "${state.receivedCount}/${state.totalChunks} chunks")
        } else {
            Log.i(TAG, "Emitting complete voice message ${state.messageId}")
        }
    }

    /**
     * Concatenate chunks in order, filling silence for missing ones.
     * Returns a valid AMR-NB byte stream (with file header).
     *
     * Missing chunks are replaced with the correct number of silence frames
     * based on the bitrate's frame size, preserving audio timeline alignment.
     */
    private fun assembleAudio(state: AssemblyState): ByteArray {
        val output = ByteArrayOutputStream()
        val bitrate = AmrNbBitrate.entries.getOrElse(state.bitrateIndex) { AmrNbBitrate.MR795 }

        // Write AMR-NB file header (chunks carry raw frames, no file header)
        output.write(AMR_HEADER)

        // Write chunks in order
        for (i in 0 until state.totalChunks) {
            val chunkPayload = state.chunks[i]
            if (chunkPayload != null) {
                output.write(chunkPayload)
            } else {
                // Calculate how many AMR frames would fit in a full chunk payload,
                // then emit that many silence frames to preserve timing.
                val expectedPayloadSize = VoiceChunker.MAX_PAYLOAD_SIZE
                val silenceFrameCount = bitrate.framesIn(expectedPayloadSize).coerceAtLeast(1)
                repeat(silenceFrameCount) {
                    output.write(SILENCE_FRAME)
                }
            }
        }

        return output.toByteArray()
    }

    /**
     * Track a recently-completed message to reject late duplicate chunks.
     * Evicts entries older than [BLACKLIST_EXPIRY_MS] and caps at [MAX_BLACKLIST_SIZE].
     */
    private fun addToBlacklist(key: AssemblyKey) {
        val now = System.currentTimeMillis()

        // Evict expired entries
        val iterator = recentlyCompleted.entries.iterator()
        while (iterator.hasNext()) {
            val entry = iterator.next()
            if (now - entry.value > BLACKLIST_EXPIRY_MS) {
                iterator.remove()
            } else {
                break // LinkedHashMap is insertion-ordered, so later entries are newer
            }
        }

        // Cap size
        while (recentlyCompleted.size >= MAX_BLACKLIST_SIZE) {
            recentlyCompleted.entries.iterator().let { it.next(); it.remove() }
        }

        recentlyCompleted[key] = now
    }

    /**
     * Get the number of messages currently being assembled.
     */
    fun pendingCount(): Int = runBlocking { mutex.withLock { assemblies.size } }

    /**
     * Clear all pending assemblies and cancel timeouts.
     */
    fun clear() {
        runBlocking {
            mutex.withLock {
                assemblies.values.forEach { it.timeoutJob?.cancel() }
                assemblies.clear()
                recentlyCompleted.clear()
            }
        }
    }

    /**
     * Shut down the assembler and release resources.
     */
    fun destroy() {
        clear()
        scope.cancel()
    }
}

package re.chasam.voicetastic.voice

import re.chasam.voicetastic.model.AmrNbBitrate
import java.nio.ByteBuffer
import java.nio.ByteOrder

/**
 * Splits AMR-NB audio data into mesh-compatible chunks.
 *
 * Chunk format (total max 230 bytes per Meshtastic packet):
 * - Header: 6 bytes
 *   - [0..1] messageId (UInt16, big-endian) — unique voice message identifier
 *   - [2..3] chunkIndex (UInt16, big-endian) — 0-based chunk index
 *   - [4]    totalChunks (UInt8) — total number of chunks (max 255)
 *   - [5]    bitrateIndex (UInt8) — index into AmrNbBitrate enum
 * - Payload: up to 224 bytes of AMR-NB audio data
 */
object VoiceChunker {

    const val HEADER_SIZE = 6
    const val MAX_PACKET_SIZE = 230
    const val MAX_PAYLOAD_SIZE = MAX_PACKET_SIZE - HEADER_SIZE // 224

    /**
     * Split audio data into numbered chunks ready for transmission.
     *
     * @param audioData raw AMR-NB file bytes (including AMR header)
     * @param messageId unique message identifier (will be truncated to UInt16)
     * @param bitrate the AMR-NB bitrate used for encoding
     * @return list of chunk byte arrays, each ready to send as a mesh data packet
     * @throws IllegalArgumentException if audio data would require more than 255 chunks
     */
    fun chunkAudio(audioData: ByteArray, messageId: Int, bitrate: AmrNbBitrate): List<ByteArray> {
        if (audioData.isEmpty()) return emptyList()

        val totalChunks = (audioData.size + MAX_PAYLOAD_SIZE - 1) / MAX_PAYLOAD_SIZE
        require(totalChunks <= 255) {
            "Audio data too large: $totalChunks chunks needed (max 255). " +
                    "Data size: ${audioData.size} bytes"
        }

        val chunks = mutableListOf<ByteArray>()
        var offset = 0
        var index = 0

        while (offset < audioData.size) {
            val payloadSize = minOf(MAX_PAYLOAD_SIZE, audioData.size - offset)
            val chunk = ByteArray(HEADER_SIZE + payloadSize)

            // Write header
            writeHeader(chunk, messageId, index, totalChunks, bitrate)

            // Copy audio payload
            System.arraycopy(audioData, offset, chunk, HEADER_SIZE, payloadSize)

            chunks.add(chunk)
            offset += payloadSize
            index++
        }

        return chunks
    }

    /**
     * Parse the header from a chunk.
     * @return ChunkHeader with parsed fields, or null if data is too short
     */
    fun parseHeader(chunk: ByteArray): ChunkHeader? {
        if (chunk.size < HEADER_SIZE) return null

        val buf = ByteBuffer.wrap(chunk, 0, HEADER_SIZE).order(ByteOrder.BIG_ENDIAN)
        val msgId = buf.short.toInt() and 0xFFFF
        val chunkIdx = buf.short.toInt() and 0xFFFF
        val total = chunk[4].toInt() and 0xFF
        val bitrateIdx = chunk[5].toInt() and 0xFF

        return ChunkHeader(msgId, chunkIdx, total, bitrateIdx)
    }

    /**
     * Extract the audio payload from a chunk (everything after the header).
     */
    fun extractPayload(chunk: ByteArray): ByteArray {
        if (chunk.size <= HEADER_SIZE) return ByteArray(0)
        return chunk.copyOfRange(HEADER_SIZE, chunk.size)
    }

    private fun writeHeader(
        chunk: ByteArray,
        messageId: Int,
        chunkIndex: Int,
        totalChunks: Int,
        bitrate: AmrNbBitrate
    ) {
        val buf = ByteBuffer.wrap(chunk, 0, HEADER_SIZE).order(ByteOrder.BIG_ENDIAN)
        buf.putShort((messageId and 0xFFFF).toShort())
        buf.putShort((chunkIndex and 0xFFFF).toShort())
        chunk[4] = (totalChunks and 0xFF).toByte()
        chunk[5] = bitrate.ordinal.toByte()
    }

    /**
     * Parsed chunk header.
     */
    data class ChunkHeader(
        val messageId: Int,
        val chunkIndex: Int,
        val totalChunks: Int,
        val bitrateIndex: Int
    ) {
        val bitrate: AmrNbBitrate
            get() = AmrNbBitrate.entries.getOrElse(bitrateIndex) { AmrNbBitrate.MR795 }
    }
}

package re.chasam.voicetastic.voice

import re.chasam.voicetastic.model.AmrNbBitrate
import java.nio.ByteBuffer
import java.nio.ByteOrder

/**
 * Splits AMR-NB audio data into mesh-compatible chunks.
 *
 * **Protocol v1** chunk format (total max 231 bytes per Meshtastic packet):
 * - Header: 6 bytes
 *   - [0]    version    (UInt8) — protocol version, currently 1
 *   - [1..2] messageId  (UInt16, big-endian) — unique voice message identifier
 *   - [3]    chunkIndex (UInt8) — 0-based chunk index (max 255)
 *   - [4]    totalChunks(UInt8) — total number of chunks (max 255)
 *   - [5]    bitrateIndex(UInt8) — index into AmrNbBitrate enum
 * - Payload: up to 225 bytes of raw AMR-NB frame data (no AMR file header)
 *
 * The AMR-NB file header (`#!AMR\n`) is stripped before chunking on the sender
 * side and prepended during reassembly on the receiver side. This avoids the
 * duplicate-header bug and saves 6 bytes in chunk 0.
 */
object VoiceChunker {

    const val PROTOCOL_VERSION = 1
    const val HEADER_SIZE = 6
    const val MAX_PACKET_SIZE = 231
    const val MAX_PAYLOAD_SIZE = MAX_PACKET_SIZE - HEADER_SIZE // 225

    /** AMR-NB file header: "#!AMR\n" */
    val AMR_FILE_HEADER = byteArrayOf(0x23, 0x21, 0x41, 0x4D, 0x52, 0x0A)

    /**
     * Split audio data into numbered chunks ready for transmission.
     *
     * The AMR-NB file header is automatically stripped if present.
     * On the receive side, [VoiceAssembler] re-adds it during reassembly.
     *
     * @param audioData raw AMR-NB file bytes (may include AMR file header)
     * @param messageId unique message identifier (will be truncated to UInt16)
     * @param bitrate the AMR-NB bitrate used for encoding
     * @return list of chunk byte arrays, each ready to send as a mesh data packet
     * @throws IllegalArgumentException if audio data would require more than 255 chunks
     */
    fun chunkAudio(audioData: ByteArray, messageId: Int, bitrate: AmrNbBitrate): List<ByteArray> {
        if (audioData.isEmpty()) return emptyList()

        // Strip AMR file header if present
        val frameData = stripAmrHeader(audioData)
        if (frameData.isEmpty()) return emptyList()

        val totalChunks = (frameData.size + MAX_PAYLOAD_SIZE - 1) / MAX_PAYLOAD_SIZE
        require(totalChunks <= 255) {
            "Audio data too large: $totalChunks chunks needed (max 255). " +
                    "Data size: ${frameData.size} bytes"
        }

        val chunks = mutableListOf<ByteArray>()
        var offset = 0
        var index = 0

        while (offset < frameData.size) {
            val payloadSize = minOf(MAX_PAYLOAD_SIZE, frameData.size - offset)
            val chunk = ByteArray(HEADER_SIZE + payloadSize)

            // Write header
            writeHeader(chunk, messageId, index, totalChunks, bitrate)

            // Copy audio payload
            System.arraycopy(frameData, offset, chunk, HEADER_SIZE, payloadSize)

            chunks.add(chunk)
            offset += payloadSize
            index++
        }

        return chunks
    }

    /**
     * Parse the header from a chunk.
     * @return ChunkHeader with parsed fields, or null if data is too short or version is unknown
     */
    fun parseHeader(chunk: ByteArray): ChunkHeader? {
        if (chunk.size < HEADER_SIZE) return null

        val version = chunk[0].toInt() and 0xFF
        if (version != PROTOCOL_VERSION) return null

        val buf = ByteBuffer.wrap(chunk, 1, 2).order(ByteOrder.BIG_ENDIAN)
        val msgId = buf.short.toInt() and 0xFFFF
        val chunkIdx = chunk[3].toInt() and 0xFF
        val total = chunk[4].toInt() and 0xFF
        val bitrateIdx = chunk[5].toInt() and 0xFF

        return ChunkHeader(version, msgId, chunkIdx, total, bitrateIdx)
    }

    /**
     * Extract the audio payload from a chunk (everything after the header).
     */
    fun extractPayload(chunk: ByteArray): ByteArray {
        if (chunk.size <= HEADER_SIZE) return ByteArray(0)
        return chunk.copyOfRange(HEADER_SIZE, chunk.size)
    }

    /**
     * Strip the AMR-NB file header (#!AMR\n) if present.
     * Returns audio frame data without the file header.
     */
    internal fun stripAmrHeader(data: ByteArray): ByteArray {
        if (data.size >= AMR_FILE_HEADER.size) {
            val prefix = data.copyOfRange(0, AMR_FILE_HEADER.size)
            if (prefix.contentEquals(AMR_FILE_HEADER)) {
                return data.copyOfRange(AMR_FILE_HEADER.size, data.size)
            }
        }
        // No AMR header found — assume raw frame data
        return data
    }

    private fun writeHeader(
        chunk: ByteArray,
        messageId: Int,
        chunkIndex: Int,
        totalChunks: Int,
        bitrate: AmrNbBitrate
    ) {
        chunk[0] = PROTOCOL_VERSION.toByte()
        val buf = ByteBuffer.wrap(chunk, 1, 2).order(ByteOrder.BIG_ENDIAN)
        buf.putShort((messageId and 0xFFFF).toShort())
        chunk[3] = (chunkIndex and 0xFF).toByte()
        chunk[4] = (totalChunks and 0xFF).toByte()
        chunk[5] = bitrate.ordinal.toByte()
    }

    /**
     * Parsed chunk header.
     */
    data class ChunkHeader(
        val version: Int,
        val messageId: Int,
        val chunkIndex: Int,
        val totalChunks: Int,
        val bitrateIndex: Int
    ) {
        val bitrate: AmrNbBitrate
            get() = AmrNbBitrate.entries.getOrElse(bitrateIndex) { AmrNbBitrate.MR795 }
    }
}

package re.chasam.voicetastic.model
import android.media.MediaRecorder
/** * Configuration for voice messages. * * @param bitrate AMR-NB bitrate (use MediaRecorder.AudioEncoder AMR_NB bitrate values) * @param maxDurationSeconds Maximum recording duration in seconds (1–60) * @param chunkTimeoutSeconds Timeout for receiving all chunks of a voice message */ data class VoiceConfig( val bitrate: AmrNbBitrate = AmrNbBitrate.MR795, val maxDurationSeconds: Int = 20, val chunkTimeoutSeconds: Int = 30, val partialPlayOnTimeout: Boolean = true )
/** * AMR-NB bitrate modes. * The actual bitrate in bits/s and approximate bytes/second are listed. */ enum class AmrNbBitrate(val bps: Int, val label: String) { MR475(4750, "4.75 kbps"), MR515(5150, "5.15 kbps"), MR59(5900, "5.9 kbps"), MR67(6700, "6.7 kbps"), MR74(7400, "7.4 kbps"), MR795(7950, "7.95 kbps"), MR102(10200, "10.2 kbps"), MR122(12200, "12.2 kbps");
/** Approximate bytes per second of encoded audio */ val bytesPerSecond: Int get() = bps / 8 }

package re.chasam.voicetastic.model
import android.media.MediaRecorder
/** * Configuration for voice messages. * * @param bitrate AMR-NB bitrate (use MediaRecorder.AudioEncoder AMR_NB bitrate values) * @param maxDurationSeconds Maximum recording duration in seconds (1–60) * @param chunkTimeoutSeconds Timeout for receiving all chunks of a voice message */ data class VoiceConfig( val bitrate: AmrNbBitrate = AmrNbBitrate.MR795, val maxDurationSeconds: Int = 20, val chunkTimeoutSeconds: Int = 30, val partialPlayOnTimeout: Boolean = true )
/** * AMR-NB bitrate modes. * The actual bitrate in bits/s and approximate bytes/second are listed. * Each 20 ms frame has a fixed size (including 1-byte frame header) per mode. */ enum class AmrNbBitrate(val bps: Int, val label: String, val frameSizeBytes: Int) { MR475(4750, "4.75 kbps", 13), MR515(5150, "5.15 kbps", 14), MR59(5900, "5.9 kbps", 16), MR67(6700, "6.7 kbps", 18), MR74(7400, "7.4 kbps", 20), MR795(7950, "7.95 kbps", 21), MR102(10200, "10.2 kbps", 27), MR122(12200, "12.2 kbps", 32);
/** Approximate bytes per second of encoded audio */ val bytesPerSecond: Int get() = bps / 8
/** Number of 20 ms frames that fit in a given number of bytes */ fun framesIn(bytes: Int): Int = if (frameSizeBytes > 0) bytes / frameSizeBytes else 0 }

package re.chasam.voicetastic.bdd

import io.cucumber.java.en.Given
import io.cucumber.java.en.When
import io.cucumber.java.en.Then
import io.cucumber.java.Before
import io.kotest.matchers.shouldBe
import io.kotest.matchers.booleans.shouldBeTrue
import io.kotest.matchers.booleans.shouldBeFalse
import io.kotest.matchers.collections.shouldHaveSize
import io.kotest.matchers.ints.shouldBeGreaterThan
import io.kotest.matchers.ints.shouldBeLessThanOrEqual
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.first
import re.chasam.voicetastic.model.AmrNbBitrate
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.model.VoiceMessage
import re.chasam.voicetastic.service.Portnums
import re.chasam.voicetastic.voice.VoiceAssembler
import re.chasam.voicetastic.voice.VoiceChunker

class VoiceMessagingSteps {

    private var audioData: ByteArray = ByteArray(0)
    private var chunks: List<ByteArray> = emptyList()
    private var assembler: VoiceAssembler? = null
    private var assembledMessages: MutableList<VoiceMessage> = mutableListOf()
    private var voiceConfig = VoiceConfig()
    private var currentBitrate = AmrNbBitrate.MR795
    private var maxDuration = 20
    private var testScope: CoroutineScope? = null
    private var preparedChunks: Map<Int, ByteArray> = emptyMap()

    @Before
    fun setup() {
        audioData = ByteArray(0)
        chunks = emptyList()
        assembledMessages.clear()
        voiceConfig = VoiceConfig()
        currentBitrate = AmrNbBitrate.MR795
        maxDuration = 20
        testScope?.cancel()
        testScope = CoroutineScope(Dispatchers.Default + SupervisorJob())
        assembler?.destroy()
        assembler = null
    }

    // --- Given steps ---

    @Given("the voice bitrate is set to {string}")
    fun setBitrate(bitrateLabel: String) {
        currentBitrate = AmrNbBitrate.entries.first { it.label == bitrateLabel }
        voiceConfig = voiceConfig.copy(bitrate = currentBitrate)
    }

    @Given("the max recording duration is {int} seconds")
    fun setMaxDuration(seconds: Int) {
        maxDuration = seconds
        voiceConfig = voiceConfig.copy(maxDurationSeconds = seconds)
    }

    @Given("I have AMR-NB audio data of {int} bytes")
    fun haveAudioData(size: Int) {
        audioData = ByteArray(size) { (it % 256).toByte() }
    }

    @Given("a voice message with ID {int} has {int} chunks")
    fun prepareVoiceMessage(messageId: Int, chunkCount: Int) {
        // Create audio data that produces the desired number of chunks
        val dataSize = chunkCount * VoiceChunker.MAX_PAYLOAD_SIZE
        audioData = ByteArray(dataSize) { (it % 200).toByte() }
        val allChunks = VoiceChunker.chunkAudio(audioData, messageId, currentBitrate)
        preparedChunks = allChunks.mapIndexed { idx, chunk -> idx to chunk }.toMap()

        // Initialize assembler
        assembler = VoiceAssembler(
            chunkTimeoutSeconds = voiceConfig.chunkTimeoutSeconds,
            partialPlayOnTimeout = voiceConfig.partialPlayOnTimeout,
            scope = testScope!!
        )
    }

    @Given("the chunk timeout is set to {int} seconds")
    fun setChunkTimeout(seconds: Int) {
        voiceConfig = voiceConfig.copy(chunkTimeoutSeconds = seconds)
        // Re-initialize assembler with new timeout
        assembler?.destroy()
        assembler = VoiceAssembler(
            chunkTimeoutSeconds = seconds,
            partialPlayOnTimeout = true,
            scope = testScope!!
        )
    }

    // --- When steps ---

    @When("I start recording a voice message")
    fun startRecording() {
        // Simulated - actual recording requires Android context
    }

    @When("I stop recording after {int} seconds")
    fun stopRecordingAfter(seconds: Int) {
        // Simulated - creates sample audio data
        val estimatedSize = currentBitrate.bytesPerSecond * seconds
        audioData = ByteArray(estimatedSize) { (it % 128).toByte() }
    }

    @When("the audio is chunked with message ID {int}")
    fun chunkAudio(messageId: Int) {
        chunks = VoiceChunker.chunkAudio(audioData, messageId, currentBitrate)
    }

    @When("all {int} chunks arrive from {string} in order")
    fun allChunksArrive(count: Int, sender: String) {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            delay(100)
            for (i in 0 until count) {
                assembler!!.onChunkReceived(sender, preparedChunks[i]!!)
            }
            delay(500)
            collectJob.cancel()
        }
    }

    @When("chunk {int} arrives from {string}")
    fun chunkArrives(index: Int, sender: String) {
        assembler!!.onChunkReceived(sender, preparedChunks[index]!!)
    }

    @When("only chunks {int} and {int} arrive from {string}")
    fun partialChunksArrive(idx1: Int, idx2: Int, sender: String) {
        assembler!!.onChunkReceived(sender, preparedChunks[idx1]!!)
        assembler!!.onChunkReceived(sender, preparedChunks[idx2]!!)
    }

    @When("I wait for the chunk timeout to expire")
    fun waitForTimeout() {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            // Wait longer than the timeout
            delay((voiceConfig.chunkTimeoutSeconds * 1000L) + 2000)
            collectJob.cancel()
        }
    }

    @When("{int} seconds elapse")
    fun secondsElapse(seconds: Int) {
        // Simulated for max duration test
    }

    @When("the same chunk arrives {int} times from {string}")
    fun sameChunkMultipleTimes(times: Int, sender: String) {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            delay(100)
            val chunk = preparedChunks[0]!!
            repeat(times) {
                assembler!!.onChunkReceived(sender, chunk)
            }
            delay(500)
            collectJob.cancel()
        }
    }

    // --- Then steps ---

    @Then("the recording should produce AMR-NB audio data")
    fun recordingProducesAmrData() {
        audioData.size shouldBeGreaterThan 0
    }

    @Then("the audio should be chunked into packets of at most {int} bytes each")
    fun chunksAreCorrectSize(maxSize: Int) {
        chunks = VoiceChunker.chunkAudio(audioData, 1, currentBitrate)
        chunks.forEach { chunk ->
            chunk.size shouldBeLessThanOrEqual maxSize
        }
    }

    @Then("each chunk should have a 6-byte header with message ID, chunk index, total chunks, and bitrate")
    fun chunksHaveValidHeaders() {
        chunks.forEachIndexed { idx, chunk ->
            val header = VoiceChunker.parseHeader(chunk)!!
            header.version shouldBe VoiceChunker.PROTOCOL_VERSION
            header.chunkIndex shouldBe idx
            header.totalChunks shouldBe chunks.size
        }
    }

    @Then("the chunks should be sent via the PRIVATE_APP port")
    fun chunksSentViaPrivatePort() {
        // Verified by architecture - VoiceViewModel sends on Portnums.PRIVATE_APP
        Portnums.PRIVATE_APP shouldBe 256
    }

    @Then("it should produce {int} chunks")
    fun producesNChunks(expected: Int) {
        chunks shouldHaveSize expected
    }

    @Then("reassembling the chunk payloads should produce the original {int} bytes")
    fun reassemblyMatchesOriginal(size: Int) {
        val reassembled = chunks.flatMap { VoiceChunker.extractPayload(it).toList() }.toByteArray()
        // VoiceChunker strips the AMR file header before chunking, so
        // reassembled payloads match the input with AMR header stripped.
        val expected = VoiceChunker.stripAmrHeader(audioData)
        reassembled shouldBe expected
    }

    @Then("a complete voice message should be assembled")
    fun completeMessageAssembled() {
        assembledMessages.size shouldBeGreaterThan 0
    }

    @Then("the voice message should be marked as complete")
    fun messageIsComplete() {
        assembledMessages.last().isComplete.shouldBeTrue()
    }

    @Then("the voice message should be playable")
    fun messageIsPlayable() {
        val msg = assembledMessages.last()
        msg.audioData.size shouldBeGreaterThan 0
        // Should start with AMR header
        msg.audioData.take(6).toByteArray() shouldBe VoiceAssembler.AMR_HEADER
    }

    @Then("a partial voice message should be assembled")
    fun partialMessageAssembled() {
        assembledMessages.size shouldBeGreaterThan 0
        assembledMessages.last().isComplete.shouldBeFalse()
    }

    @Then("the voice message should have {int} received chunks out of {int} total")
    fun messageHasChunkCounts(received: Int, total: Int) {
        val msg = assembledMessages.last()
        msg.receivedChunks shouldBe received
        msg.totalChunks shouldBe total
    }

    @Then("missing chunks should be replaced with silence frames")
    fun missingChunksAreSilence() {
        val msg = assembledMessages.last()
        // Audio data should exist (AMR header + some data)
        msg.audioData.size shouldBeGreaterThan VoiceAssembler.AMR_HEADER.size
    }

    @Then("the recording should stop automatically")
    fun recordingStopsAutomatically() {
        // Simulated - VoiceRecorder sets max duration on MediaRecorder
        voiceConfig.maxDurationSeconds shouldBe maxDuration
    }

    @Then("each chunk header should contain bitrate index {int}")
    fun chunkHeaderHasBitrateIndex(expectedIndex: Int) {
        chunks.forEach { chunk ->
            val header = VoiceChunker.parseHeader(chunk)!!
            header.bitrateIndex shouldBe expectedIndex
        }
    }

    @Then("exactly {int} voice message should be assembled")
    fun exactlyNMessagesAssembled(count: Int) {
        assembledMessages shouldHaveSize count
    }

    @Then("it should be marked as complete")
    fun itIsComplete() {
        assembledMessages.last().isComplete.shouldBeTrue()
    }
}

package re.chasam.voicetastic.bdd

import io.cucumber.java.en.Given
import io.cucumber.java.en.When
import io.cucumber.java.en.Then
import io.cucumber.java.Before
import io.kotest.matchers.shouldBe
import io.kotest.matchers.booleans.shouldBeTrue
import io.kotest.matchers.booleans.shouldBeFalse
import io.kotest.matchers.collections.shouldHaveSize
import io.kotest.matchers.ints.shouldBeGreaterThan
import io.kotest.matchers.ints.shouldBeLessThanOrEqual
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.first
import re.chasam.voicetastic.model.AmrNbBitrate
import re.chasam.voicetastic.model.VoiceConfig
import re.chasam.voicetastic.model.VoiceMessage
import re.chasam.voicetastic.service.Portnums
import re.chasam.voicetastic.voice.VoiceAssembler
import re.chasam.voicetastic.voice.VoiceChunker

class VoiceMessagingSteps {

    private var audioData: ByteArray = ByteArray(0)
    private var chunks: List<ByteArray> = emptyList()
    private var assembler: VoiceAssembler? = null
    private var assembledMessages: MutableList<VoiceMessage> = mutableListOf()
    private var voiceConfig = VoiceConfig()
    private var currentBitrate = AmrNbBitrate.MR795
    private var maxDuration = 20
    private var testScope: CoroutineScope? = null
    private var preparedChunks: Map<Int, ByteArray> = emptyMap()

    @Before
    fun setup() {
        audioData = ByteArray(0)
        chunks = emptyList()
        assembledMessages.clear()
        voiceConfig = VoiceConfig()
        currentBitrate = AmrNbBitrate.MR795
        maxDuration = 20
        testScope?.cancel()
        testScope = CoroutineScope(Dispatchers.Default + SupervisorJob())
        assembler?.destroy()
        assembler = null
    }

    // --- Given steps ---

    @Given("the voice bitrate is set to {string}")
    fun setBitrate(bitrateLabel: String) {
        currentBitrate = AmrNbBitrate.entries.first { it.label == bitrateLabel }
        voiceConfig = voiceConfig.copy(bitrate = currentBitrate)
    }

    @Given("the max recording duration is {int} seconds")
    fun setMaxDuration(seconds: Int) {
        maxDuration = seconds
        voiceConfig = voiceConfig.copy(maxDurationSeconds = seconds)
    }

    @Given("I have AMR-NB audio data of {int} bytes")
    fun haveAudioData(size: Int) {
        audioData = ByteArray(size) { (it % 256).toByte() }
    }

    @Given("a voice message with ID {int} has {int} chunks")
    fun prepareVoiceMessage(messageId: Int, chunkCount: Int) {
        // Create audio data that produces the desired number of chunks
        val dataSize = chunkCount * VoiceChunker.MAX_PAYLOAD_SIZE
        audioData = ByteArray(dataSize) { (it % 200).toByte() }
        val allChunks = VoiceChunker.chunkAudio(audioData, messageId, currentBitrate)
        preparedChunks = allChunks.mapIndexed { idx, chunk -> idx to chunk }.toMap()

        // Initialize assembler
        assembler = VoiceAssembler(
            chunkTimeoutSeconds = voiceConfig.chunkTimeoutSeconds,
            partialPlayOnTimeout = voiceConfig.partialPlayOnTimeout,
            scope = testScope!!
        )
    }

    @Given("the chunk timeout is set to {int} seconds")
    fun setChunkTimeout(seconds: Int) {
        voiceConfig = voiceConfig.copy(chunkTimeoutSeconds = seconds)
        // Re-initialize assembler with new timeout
        assembler?.destroy()
        assembler = VoiceAssembler(
            chunkTimeoutSeconds = seconds,
            partialPlayOnTimeout = true,
            scope = testScope!!
        )
    }

    // --- When steps ---

    @When("I start recording a voice message")
    fun startRecording() {
        // Simulated - actual recording requires Android context
    }

    @When("I stop recording after {int} seconds")
    fun stopRecordingAfter(seconds: Int) {
        // Simulated - creates sample audio data
        val estimatedSize = currentBitrate.bytesPerSecond * seconds
        audioData = ByteArray(estimatedSize) { (it % 128).toByte() }
    }

    @When("the audio is chunked with message ID {int}")
    fun chunkAudio(messageId: Int) {
        chunks = VoiceChunker.chunkAudio(audioData, messageId, currentBitrate)
    }

    @When("all {int} chunks arrive from {string} in order")
    fun allChunksArrive(count: Int, sender: String) {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            delay(100)
            for (i in 0 until count) {
                assembler!!.onChunkReceived(sender, preparedChunks[i]!!)
            }
            delay(1000) // allow async mutex-guarded processing
            collectJob.cancel()
        }
    }

    @When("chunk {int} arrives from {string}")
    fun chunkArrives(index: Int, sender: String) {
        assembler!!.onChunkReceived(sender, preparedChunks[index]!!)
    }

    @When("only chunks {int} and {int} arrive from {string}")
    fun partialChunksArrive(idx1: Int, idx2: Int, sender: String) {
        assembler!!.onChunkReceived(sender, preparedChunks[idx1]!!)
        assembler!!.onChunkReceived(sender, preparedChunks[idx2]!!)
    }

    @When("I wait for the chunk timeout to expire")
    fun waitForTimeout() {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            // Wait longer than the timeout
            delay((voiceConfig.chunkTimeoutSeconds * 1000L) + 2000)
            collectJob.cancel()
        }
    }

    @When("{int} seconds elapse")
    fun secondsElapse(seconds: Int) {
        // Simulated for max duration test
    }

    @When("the same chunk arrives {int} times from {string}")
    fun sameChunkMultipleTimes(times: Int, sender: String) {
        runBlocking {
            val collectJob = testScope!!.launch {
                assembler!!.completedMessages.collect { assembledMessages.add(it) }
            }
            delay(100)
            val chunk = preparedChunks[0]!!
            repeat(times) {
                assembler!!.onChunkReceived(sender, chunk)
            }
            delay(500)
            collectJob.cancel()
        }
    }

    // --- Then steps ---

    @Then("the recording should produce AMR-NB audio data")
    fun recordingProducesAmrData() {
        audioData.size shouldBeGreaterThan 0
    }

    @Then("the audio should be chunked into packets of at most {int} bytes each")
    fun chunksAreCorrectSize(maxSize: Int) {
        chunks = VoiceChunker.chunkAudio(audioData, 1, currentBitrate)
        chunks.forEach { chunk ->
            chunk.size shouldBeLessThanOrEqual maxSize
        }
    }

    @Then("each chunk should have a 6-byte header with message ID, chunk index, total chunks, and bitrate")
    fun chunksHaveValidHeaders() {
        chunks.forEachIndexed { idx, chunk ->
            val header = VoiceChunker.parseHeader(chunk)!!
            header.version shouldBe VoiceChunker.PROTOCOL_VERSION
            header.chunkIndex shouldBe idx
            header.totalChunks shouldBe chunks.size
        }
    }

    @Then("the chunks should be sent via the PRIVATE_APP port")
    fun chunksSentViaPrivatePort() {
        // Verified by architecture - VoiceViewModel sends on Portnums.PRIVATE_APP
        Portnums.PRIVATE_APP shouldBe 256
    }

    @Then("it should produce {int} chunks")
    fun producesNChunks(expected: Int) {
        chunks shouldHaveSize expected
    }

    @Then("reassembling the chunk payloads should produce the original {int} bytes")
    fun reassemblyMatchesOriginal(size: Int) {
        val reassembled = chunks.flatMap { VoiceChunker.extractPayload(it).toList() }.toByteArray()
        // VoiceChunker strips the AMR file header before chunking, so
        // reassembled payloads match the input with AMR header stripped.
        val expected = VoiceChunker.stripAmrHeader(audioData)
        reassembled shouldBe expected
    }

    @Then("a complete voice message should be assembled")
    fun completeMessageAssembled() {
        assembledMessages.size shouldBeGreaterThan 0
    }

    @Then("the voice message should be marked as complete")
    fun messageIsComplete() {
        assembledMessages.last().isComplete.shouldBeTrue()
    }

    @Then("the voice message should be playable")
    fun messageIsPlayable() {
        val msg = assembledMessages.last()
        msg.audioData.size shouldBeGreaterThan 0
        // Should start with AMR header
        msg.audioData.take(6).toByteArray() shouldBe VoiceAssembler.AMR_HEADER
    }

    @Then("a partial voice message should be assembled")
    fun partialMessageAssembled() {
        assembledMessages.size shouldBeGreaterThan 0
        assembledMessages.last().isComplete.shouldBeFalse()
    }

    @Then("the voice message should have {int} received chunks out of {int} total")
    fun messageHasChunkCounts(received: Int, total: Int) {
        val msg = assembledMessages.last()
        msg.receivedChunks shouldBe received
        msg.totalChunks shouldBe total
    }

    @Then("missing chunks should be replaced with silence frames")
    fun missingChunksAreSilence() {
        val msg = assembledMessages.last()
        // Audio data should exist (AMR header + some data)
        msg.audioData.size shouldBeGreaterThan VoiceAssembler.AMR_HEADER.size
    }

    @Then("the recording should stop automatically")
    fun recordingStopsAutomatically() {
        // Simulated - VoiceRecorder sets max duration on MediaRecorder
        voiceConfig.maxDurationSeconds shouldBe maxDuration
    }

    @Then("each chunk header should contain bitrate index {int}")
    fun chunkHeaderHasBitrateIndex(expectedIndex: Int) {
        chunks.forEach { chunk ->
            val header = VoiceChunker.parseHeader(chunk)!!
            header.bitrateIndex shouldBe expectedIndex
        }
    }

    @Then("exactly {int} voice message should be assembled")
    fun exactlyNMessagesAssembled(count: Int) {
        assembledMessages shouldHaveSize count
    }

    @Then("it should be marked as complete")
    fun itIsComplete() {
        assembledMessages.last().isComplete.shouldBeTrue()
    }
}
